import { GoogleGenAI } from "@google/genai";
import { VisaRequestParams, VisaInfoResponse, GroundingChunk } from "../types";

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

export const getVisaRequirements = async (params: VisaRequestParams): Promise<VisaInfoResponse> => {
  try {
    const model = 'gemini-2.5-flash';

    // Get current date for context
    const today = new Date().toLocaleDateString('ar-EG', { year: 'numeric', month: 'long', day: 'numeric' });

    // Country Specific Overrides
    const destCode = params.destination.code;
    const originCode = params.origin.code;
    let specialInstructions = "";

    // --- CANADIAN VISA SUBSTITUTION RULES (Primarily for Egyptians/General) ---
    // This applies if the user holds a valid Canadian Visa.
    const canadaVisaExemptions = `
      **⚡ IMPORTANT NOTE: VALID CANADIAN VISA HOLDERS EXEMPTIONS**
      If the applicant holds a valid, used, or multi-entry **Canadian Visa**, include this SPECIFIC exemption rule for ${params.destination.nameEn}:
    `;

    if (destCode === 'MX') {
      specialInstructions += `
      ${canadaVisaExemptions}
      - **Mexico**: ENTRY ALLOWED WITHOUT MEXICO VISA.
      - **Condition**: Must hold a valid **Multi-Entry Canadian Visa**.
      - **Max Stay**: Up to 180 days.
      `;
    } else if (destCode === 'CR') {
       specialInstructions += `
      ${canadaVisaExemptions}
      - **Costa Rica**: ENTRY ALLOWED.
      - **Condition**: Valid tourist, business, or student Canadian visa.
      - **Max Stay**: 30 days.
      `;
    } else if (destCode === 'PA') {
       specialInstructions += `
      ${canadaVisaExemptions}
      - **Panama**: ENTRY ALLOWED.
      - **Conditions**: 
        1. Canadian visa must be valid for at least 6 months.
        2. Must have been **used** to enter Canada at least once.
        3. Proof of solvency ($500).
      - **Max Stay**: 30 days.
      `;
    } else if (destCode === 'BZ') {
       specialInstructions += `
      ${canadaVisaExemptions}
      - **Belize**: ENTRY ALLOWED (Visa-free).
      - **Max Stay**: 30 days.
      `;
    } else if (destCode === 'SV') {
       specialInstructions += `
      ${canadaVisaExemptions}
      - **El Salvador**: ENTRY ALLOWED (CA-4 Zone).
      - **Fee**: $12 Tourist Card purchased at airport upon arrival.
      - **Max Stay**: 90 days.
      `;
    } else if (destCode === 'GT') {
       specialInstructions += `
      ${canadaVisaExemptions}
      - **Guatemala**: ENTRY ALLOWED (CA-4 Zone).
      - **Max Stay**: 90 days.
      `;
    } else if (destCode === 'HN') {
       specialInstructions += `
      ${canadaVisaExemptions}
      - **Honduras**: ENTRY ALLOWED (CA-4 Zone).
      - **Condition**: Canadian visa must be valid for at least 6 months.
      - **Max Stay**: 90 days.
      `;
    } else if (destCode === 'DO') {
       specialInstructions += `
      ${canadaVisaExemptions}
      - **Dominican Republic**: ENTRY ALLOWED.
      - **Fee**: Free Tourist Card upon arrival.
      - **Max Stay**: 30 days.
      `;
    } else if (destCode === 'BM') {
       specialInstructions += `
      ${canadaVisaExemptions}
      - **Bermuda**: ENTRY ALLOWED.
      - **Condition**: Canadian visa must be valid for at least 45 days **after** departure from Bermuda.
      - **Max Stay**: 30 days.
      `;
    } else if (destCode === 'AG') {
       specialInstructions += `
      ${canadaVisaExemptions}
      - **Antigua and Barbuda**: VISA ON ARRIVAL ALLOWED.
      - **Fee**: $100 USD.
      - **Condition**: Canadian visa valid for at least 6 months.
      - **Max Stay**: 30 days.
      `;
    } else if (destCode === 'GE') {
       specialInstructions += `
      ${canadaVisaExemptions}
      - **Georgia**: ENTRY ALLOWED WITHOUT VISA.
      - **Max Stay**: 90 days within any 180-day period.
      `;
    } else if (destCode === 'ME') {
       specialInstructions += `
      ${canadaVisaExemptions}
      - **Montenegro**: ENTRY ALLOWED.
      - **Max Stay**: 30 days.
      `;
    } else if (destCode === 'MK') {
       specialInstructions += `
      ${canadaVisaExemptions}
      - **North Macedonia**: ENTRY ALLOWED.
      - **Condition**: Canadian visa must be valid for at least 5 days **after** planned departure.
      - **Max Stay**: 15 days.
      `;
    } else if (destCode === 'AM') {
       specialInstructions += `
      ${canadaVisaExemptions}
      - **Armenia**: VISA ON ARRIVAL ALLOWED.
      - **Fees**: 3,000 AMD (21 days) or 15,000 AMD (120 days).
      `;
    } else if (destCode === 'GB') {
       specialInstructions += `
      ${canadaVisaExemptions}
      - **United Kingdom**: TRANSIT WITHOUT VISA (TWOV) ALLOWED.
      - **Max Stay**: 24 hours (Landside/Airside).
      - **Strict Conditions**: 
        1. Must arrive/depart from London Heathrow, Gatwick, or Manchester.
        2. Must be traveling **to** or **from** Canada with a valid Canadian visa.
        3. Must have confirmed onward flight within 24 hours.
      `;
    }

    // --- THAILAND ---
    if (destCode === 'TH') {
      specialInstructions += `
      **🚨 SPECIAL CRITICAL RULES FOR THAILAND (E-VISA) - MUST INCLUDE IN REPORT:**
      1. **Bank Statement (كشف الحساب)**: Must be **Last 3 Months** only (NOT 6). Transactions must be clear. **Official Bank Stamp (Photo/Scan)** is MANDATORY.
      2. **Employment Proof**: **Social Insurance Printout (برنت تأمينات)** is MANDATORY for employees (Translated to English). Do NOT confuse with Travel Insurance.
      3. **Travel History**: Attach copy of previous visas if available: **Thailand, Schengen, USA, or UK**.
      `;

    // --- TURKEY ---
    } else if (destCode === 'TR') {
      specialInstructions += `
      **🚨 SPECIAL CRITICAL RULES FOR TURKEY (BUSINESS & TOURISM) - MUST INCLUDE IN REPORT:**
      1. **Fees**: **Single: $203** + $5 booking. **Multi (1 Year): $369** + $5 (Requires 2 previous visas + Mandatory Invitation).
      2. **Legalization (Tawtheeq)**: 
         - **Employees**: HR Letter (Original, Stamped) **MUST BE LEGALIZED by Egyptian MFA**.
         - **Business Owners**: Commercial Register **MUST BE LEGALIZED by Egyptian MFA**.
      3. **Insurance**: **MUST be issued through the agency office ONLY**. External insurance policies are NOT accepted.
      4. **Submission**: Walk-in (No Appointment). Sun-Thu 9am-3pm.
      5. **Financials**: Last **6 Months** movement, Valid for 10 days, Stamped.
      `;

    // --- USA ---
    } else if (destCode === 'US') {
      const isRestricted = ['EG', 'SD', 'SY', 'DJ', 'MR', 'YE', 'AF', 'AO', 'LB', 'LY', 'SO'].includes(originCode);
      specialInstructions += `
      **🚨 SPECIAL CRITICAL RULES FOR USA (UPDATED) - STRICT ENFORCEMENT:**
      1. **ADDITIONAL DOCUMENTS REQUIRED**:
         - **Income/Assets**: Proof of tax payment, property ownership, or business assets.
         - **Itinerary**: Detailed travel plan (Conference reg, invitation, or bookings).
         - **Employer Letter**: Must detail Job, Salary, Tenure, Approved Leave, and Business Purpose.
         - **Criminal Record**: Required for ANY arrest/conviction, even if pardoned.
         - **Payslips**: Last **3 Months** required.
         - **Students**: Transcripts, Diplomas, and Financial Support proofs.
      2. **INTERVIEW WAIVER CANCELLED**: 
         - Citizens of **Egypt, Sudan, Syria, Yemen, Libya, etc.** MUST attend a personal interview even for renewals. **NO INTERVIEW WAIVERS ALLOWED**.
      3. **Application Location**: Must apply from country of residence/citizenship. Applying elsewhere increases rejection risk significantly.
      4. **No Refunds**: Fees are non-refundable if you apply in the wrong category or location.
      `;

    // --- CROATIA ---
    } else if (destCode === 'HR') {
      specialInstructions += `
      **🚨 SPECIAL RULES FOR CROATIA:**
      1. **Visa Fee Exemption**: Free ONLY for children **under 6 years old** (previously 12).
      2. **Child Fees**: Children aged **6 to 11 years** pay **45 Euro**.
      `;

    // --- JAPAN ---
    } else if (destCode === 'JP') {
      specialInstructions += `
      **🚨 SPECIAL RULES FOR JAPAN (UPDATED FEES):**
      1. **Fees**: Increased to **850 EGP** (Single Entry) / **1690 EGP** (Multi Entry).
      2. **Payment**: Paid in CASH upon visa collection.
      `;

    // --- BRAZIL ---
    } else if (destCode === 'BR') {
      specialInstructions += `
      **🚨 SPECIAL RULES FOR BRAZIL:**
      1. **Rejection Policy**: If rejected, applicant MUST wait **6 Months** before re-applying.
      `;

    // --- CHINA ---
    } else if (destCode === 'CN') {
      specialInstructions += `
      **🚨 SPECIAL RULES FOR CHINA (NEW FEES FROM JULY 1, 2025):**
      1. **Fees (Egyptians)**: **1890 EGP** (Single) / **2280 EGP** (Multi).
      2. **Includes**: Visa center service fees.
      `;

    // --- BULGARIA ---
    } else if (destCode === 'BG') {
      specialInstructions += `
      **🚨 SPECIAL RULES FOR BULGARIA:**
      1. **Access to Other Countries**: Valid Bulgarian visa holders can enter **Romania** and **Cyprus**.
      2. **Condition**: Must enter Bulgaria FIRST (or satisfy the specific multi-entry usage rules).
      `;

    // --- LEBANON ---
    } else if (destCode === 'LB') {
      specialInstructions += `
      **🚨 SPECIAL RULES FOR LEBANON:**
      1. **Consulate Fees**: Increased to **525 EGP** (Single) / **1050 EGP** (Multi).
      2. **Visa on Arrival**: Cost is **$17**.
      `;

    // --- ARGENTINA ---
    } else if (destCode === 'AR') {
      specialInstructions += `
      **🚨 SPECIAL RULES FOR ARGENTINA:**
      1. **Movement Certificate (Shehadet Taharokat)**:
         - Must be **Original Arabic Version**.
         - Must be **Legalized by Egyptian MFA** first.
         - Then Translated to **Spanish**.
         - *Warning*: Electronic/Digital translations often rejected if not matching the legalized original.
      `;

    // --- AUSTRALIA ---
    } else if (destCode === 'AU') {
      specialInstructions += `
      **🚨 SPECIAL RULES FOR AUSTRALIA:**
      1. **Visa Fee**: Increased to **200 AUD**.
      2. **Biometrics Fee**: **729.80 EGP** (Paid at the Visa Center).
      `;

    // --- TUNISIA ---
    } else if (destCode === 'TN') {
      specialInstructions += `
      **🚨 SPECIAL RULES FOR TUNISIA (EXEMPTIONS):**
      1. **Visa Exemptions (No Embassy application needed)** for:
         - Businessmen, Researchers, Doctors.
         - Holders of **Schengen** or **USA** visas/residence.
         - Organized Tour Groups (>10 people) via certified Tunisian agency.
      `;

    // --- MOROCCO ---
    } else if (destCode === 'MA') {
       specialInstructions += `
      **🚨 SPECIAL CRITICAL RULES FOR MOROCCO (E-VISA / AEVM):**
      1. **Eligibility for E-Visa**: You can apply for an E-Visa (AEVM) ONLY if you hold a valid visa or residence from:
         - **Australia, Canada, Ireland, Japan, New Zealand, Schengen, USA, or UK**.
      2. **STRICT CONDITIONS for the supporting visa**:
         - MUST be **Multi-Entry**.
         - MUST be valid for **MORE THAN 90 DAYS** at the time of E-Visa application.
      3. **Standard Visa**: If conditions are not met, a paper visa via the Consulate is mandatory (Appointments are difficult).
      `;

    // --- MEXICO ---
    } else if (destCode === 'MX') {
      specialInstructions += `
      **🚨 SPECIAL RULES FOR MEXICO:**
      1. **Exemption**: Visa NOT required if holding a valid **Multi-Entry** visa/residence from:
         - **USA, Canada, Japan, UK, or Schengen Area**.
      2. **Stay**: Up to 180 days.
      `;

    // --- SWEDEN ---
    } else if (destCode === 'SE') {
      specialInstructions += `
      **🚨 SPECIAL RULES FOR SWEDEN:**
      1. **Personal Invitation**: Must include **PERSONBEVIS** from Swedish Tax Agency.
      2. **Validity**: Personbevis must be less than **3 months old** at time of application.
      `;

    // --- RWANDA ---
    } else if (destCode === 'RW') {
      const isEgypt = originCode === 'EG';
      specialInstructions += `
      **🚨 SPECIAL RULES FOR RWANDA:**
      ${isEgypt ? '1. **Exemption**: **Mutual Visa Exemption** signed between Egypt and Rwanda. Entry is Visa-Free.' : ''}
      `;

    // --- KENYA ---
    } else if (destCode === 'KE') {
      const isEgypt = originCode === 'EG';
      specialInstructions += `
      **🚨 SPECIAL RULES FOR KENYA:**
      ${isEgypt ? '1. **Exemption**: **Visa-Free** for Egyptians (Stay < 60 days).' : ''}
      2. **Entry Requirements**:
         - Valid Passport.
         - **Yellow Fever Vaccination Certificate**.
         - Return Flight Ticket.
      `;
    }

    const prompt = `
      **ROLE**: ACT AS A SENIOR VISA COMPLIANCE OFFICER FOR A PROFESSIONAL VISA AGENCY.
      **TASK**: Generate a rigorous, 100% FACT-CHECKED visa requirement report.
      **AUDIENCE**: Professional Visa Agents (Require precise, actionable data, not general advice).

      **CONTEXT**:
      - Applicant Nationality: "${params.origin.nameEn} (${params.origin.nameAr})"
      - Destination: "${params.destination.nameEn} (${params.destination.nameAr})"
      - Purpose: Tourism/Business Short Stay
      - Date: ${today}

      ${specialInstructions}

      **STRICT INSTRUCTIONS**:
      1. **SOURCE TRUTH**: Prioritize official government websites (MFA, Embassies) and official service providers (VFS, TLS, BLS).
      2. **NO HALLUCINATIONS**: If a specific detail (like exact fee) is ambiguous, state "Requires verification with embassy" instead of guessing.
      3. **CURRENCY ACCURACY**: State fees in LOCAL currency of the embassy + USD/EUR equivalent.
      4. **CANADIAN VISA HOLDER**: If the country supports entry with a valid Canadian Visa based on the provided instructions, explicitly mention this as a PRIMARY OPTION in the report under "Visa Status".

      **REQUIRED OUTPUT FORMAT (MARKDOWN ARABIC):**

      # 🏛️ تقرير استحقاق التأشيرة (للاستخدام المهني)

      ## 1. حالة التأشيرة ونوعها
      *   **الحالة**: (مطلوبة / عند الوصول / إعفاء / تصريح إلكتروني)
      *   **تنبيه لحاملي تأشيرة كندا 🇨🇦**: (اذكر بوضوح إذا كان الدخول مسموحاً لحاملي تأشيرة كندا والشروط المذكورة أعلاه).
      *   **نوع التأشيرة الدقيق**: (مثلاً: Schengen Type C, B1/B2, ETA, E-Visa, Sticker)
      *   **صلاحية الإقامة المسموحة**: (مثلاً: 90 يوم خلال 180 يوم)
      *   **جهة التقديم**: (اسم المكتب الوسيط بدقة: VFS, TLS, BLS, Almaviva أو السفارة مباشرة أو الموقع الرسمي للتأشيرة الإلكترونية).
      *   **طريقة التقديم (هام)**: هل يحتاج موعد مسبق أم تقديم مباشر (Walk-in)؟ وما هي ساعات العمل؟

      ## 2. 💰 هيكل الرسوم التفصيلي (هام للشركة)
      *   **رسوم القنصلية (Consular Fee)**: [المبلغ بدقة]
      *   **رسوم المكتب الوسيط (Service Fee)**: [المبلغ بدقة إن وجد]
      *   **رسوم إضافية**: (تأمين، شحن، صور، رسوم منصة إلكترونية).
      *   *ملاحظة: هل الرسوم تدفع نقداً أم بطاقة؟*

      ## 3. 📂 قائمة المستندات (تدقيق الامتثال)
      *   **جواز السفر**: الصلاحية المطلوبة بالظبط (3 شهور بعد العودة أم 6 شهور؟) + عدد الصفحات الفارغة.
      *   **الصور الشخصية**: المقاس الدقيق (3.5x4.5 أم 5x5؟) + لون الخلفية + نسبة الوجه (Zoom).
      *   **الملاءة المالية (Bank Statement)**:
          *   المدة المطلوبة: (هل هي 3 أشهر أم 6 أشهر؟ - تحقق من القواعد الخاصة بالدولة).
          *   الحد الأدنى للرصيد (Minimum Balance): رقم تقريبي مطلوب لتغطية الرحلة.
          *   هل يقبل كشف مطبوع من التطبيق أم يحتاج ختم بنكي "Wet Stamp"؟ وهل يحتاج تصديق خارجية؟
      *   **المستندات الوظيفية**: هل يطلب برنت تأمينات اجتماعية؟ هل يحتاج خطاب العمل لتصديق الخارجية؟
      *   **حجوزات**: هل يقبل حجز مبدئي (Dummy Booking) أم مؤكد مدفوع؟
      *   **تأمين السفر**: هل هناك شروط خاصة لجهة الإصدار؟
      *   **الدعوة التجارية (إن وجدت)**: شروط قبول الدعوة وصلاحيتها.

      ## 4. ⏳ الجداول الزمنية (SLA)
      *   **وقت المعالجة الرسمي**: (من 15 إلى 45 يوم عمل مثلاً).
      *   **وضع المواعيد الحالي**: ابحث عن "Current appointment wait times for ${params.destination.nameEn} in ${params.origin.nameEn}". هل المواعيد متاحة قريباً أم مغلقة؟

      ## 5. 🚨 نقاط الرفض الحرجة (Red Flags)
      *   اذكر الأخطاء الشائعة التي تسبب رفض الملف لهذه الجنسية تحديداً.
      *   **انتبه**: راجع قسم التعليمات الخاصة أعلاه (Special Instructions) وادرج التحذيرات المذكورة فيه بدقة (مثل المقابلات الإلزامية، الأوراق المترجمة، شروط الإعفاء).

      ## 6. 🔗 الروابط الرسمية (للموظف)
      *   رابط حجز الموعد المباشر / الموقع الرسمي (إن توفر).
      *   رابط نموذج الطلب (Application Form).

      ## 7. 🗣️ نصائح مقابلة السفارة (Interview Tips)
      *   **التحضير للمقابلة**: نصائح عامة للمظهر وترتيب الملف.
      *   **أسئلة متوقعة**: (أمثلة: لماذا اخترت هذه الوجهة؟، كيف تغطي تكاليفك؟، هل ستعود لبلدك؟).
      *   **السلوك**: كيفية الإجابة بثقة واختصار.

      **STYLE**: Professional, Concise, Bullet points. No fluff.
    `;

    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
      },
    });

    const markdown = response.text || "عذراً، لم أتمكن من العثور على المعلومات المطلوبة بدقة. يرجى مراجعة السفارة مباشرة.";

    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks as GroundingChunk[] | undefined;

    const sources = groundingChunks
      ?.filter(chunk => chunk.web?.uri && chunk.web?.title)
      .map(chunk => ({
        title: chunk.web!.title,
        url: chunk.web!.uri
      })) || [];

    const uniqueSources = Array.from(new Map(sources.map(item => [item.url, item])).values());

    const result: VisaInfoResponse = {
      markdown,
      sources: uniqueSources,
      generatedAt: new Date().toISOString()
    };

    return result;

  } catch (error: any) {
    console.error("Error fetching visa info:", error);

    let errorMessage = "حدث خطأ أثناء استرجاع البيانات.";

    if (error.message) {
      if (error.message.includes('429')) errorMessage = "تجاوز الحد المسموح للطلبات.";
      else if (error.message.includes('API key')) errorMessage = "خطأ في مفتاح API.";
      else if (error.message.includes('network')) errorMessage = "خطأ في الاتصال بالإنترنت.";
    }

    throw new Error(errorMessage);
  }
};

import React, { useState, useEffect } from 'react';
import ReactMarkdown from 'react-markdown';
import { VisaInfoResponse, Country } from '../types';
import { ExternalLink, AlertCircle, Plane, CheckCircle2, AlertTriangle, Info, RefreshCw, Calculator, Upload, FileText, Trash2, Eye, Plus, X, CalendarDays, Clock, ShieldCheck, Landmark, TrendingUp, TrendingDown, PieChart, MessageCircle, Languages, Stamp, FileCheck } from 'lucide-react';
import { EXCHANGE_RATES } from '../constants';

interface VisaResultProps {
  data: VisaInfoResponse;
  origin: Country;
  destination: Country;
}

// Custom components for Markdown rendering
const MarkdownComponents = {
  h1: ({ ...props }) => <h1 className="text-2xl font-extrabold text-slate-900 dark:text-white mb-6 border-b-2 border-slate-200 dark:border-slate-700 pb-4" {...props} />,
  h2: ({ ...props }: React.HTMLAttributes<HTMLHeadingElement>) => {
    const text = typeof props.children === 'string' ? props.children : '';

    if (text.includes('رسوم') || text.includes('Fees')) {
        return (
            <div className="flex items-center gap-2 mt-8 mb-4 text-lg font-bold text-emerald-700 dark:text-emerald-400 border-r-4 border-emerald-500 pr-3 bg-emerald-50 dark:bg-emerald-900/10 py-2 rounded-l-md">
                <Calculator className="w-6 h-6" />
                <h2 {...props} />
            </div>
        )
    }
    if (text.includes('مستندات') || text.includes('Documents')) {
        return (
            <div className="flex items-center gap-2 mt-8 mb-4 text-lg font-bold text-blue-700 dark:text-blue-400 border-r-4 border-blue-500 pr-3 bg-blue-50 dark:bg-blue-900/10 py-2 rounded-l-md">
                <FileText className="w-6 h-6" />
                <h2 {...props} />
            </div>
        )
    }
    if (text.includes('رفض') || text.includes('Red Flags') || text.includes('تحذير')) {
        return (
            <div className="flex items-center gap-2 mt-8 mb-4 text-lg font-bold text-red-700 dark:text-red-400 border-r-4 border-red-500 pr-3 bg-red-50 dark:bg-red-900/10 py-2 rounded-l-md">
                <AlertTriangle className="w-6 h-6" />
                <h2 {...props} />
            </div>
        )
    }
    if (text.includes('مقابلة') || text.includes('Interview')) {
        return (
            <div className="flex items-center gap-2 mt-8 mb-4 text-lg font-bold text-purple-700 dark:text-purple-400 border-r-4 border-purple-500 pr-3 bg-purple-50 dark:bg-purple-900/10 py-2 rounded-l-md">
                <MessageCircle className="w-6 h-6" />
                <h2 {...props} />
            </div>
        )
    }

    return <h2 className="text-xl font-bold text-slate-800 dark:text-slate-200 mt-8 mb-4" {...props} />;
  },
  h3: ({ ...props }) => <h3 className="text-md font-bold text-slate-700 dark:text-slate-300 mt-4 mb-2" {...props} />,
  p: ({ ...props }) => <p className="text-slate-600 dark:text-slate-300 leading-relaxed mb-2 text-sm md:text-base" {...props} />,
  ul: ({ ...props }) => <ul className="list-disc list-inside space-y-1.5 mb-4 text-slate-600 dark:text-slate-300 bg-white dark:bg-slate-900 p-4 rounded-lg border border-slate-200 dark:border-slate-700 shadow-sm" {...props} />,
  li: ({ ...props }) => <li className="marker:text-slate-400 dark:marker:text-slate-500 pl-2" {...props} />,
  strong: ({ ...props }) => <strong className="font-bold text-slate-900 dark:text-white bg-slate-100 dark:bg-slate-800 px-1 rounded" {...props} />,
  a: ({ ...props }) => (
    <a 
      className="inline-flex items-center gap-1 text-blue-600 dark:text-blue-400 hover:underline font-medium" 
      target="_blank" 
      rel="noopener noreferrer" 
      {...props} 
    />
  ),
};

const CurrencyConverter: React.FC<{ origin: Country; destination: Country }> = ({ origin, destination }) => {
  const [amount, setAmount] = useState<number | string>(100);
  const [fromCurrency, setFromCurrency] = useState(destination.currencyCode || 'USD');
  const [toCurrency, setToCurrency] = useState(origin.currencyCode || 'SAR');
  const [result, setResult] = useState<number | null>(null);

  const currencyOptions = Array.from(new Set(['USD', 'EUR', origin.currencyCode, destination.currencyCode].filter(Boolean)));

  const handleConvert = () => {
    const val = parseFloat(amount.toString());
    if (isNaN(val)) {
      setResult(null);
      return;
    }
    const fromRate = EXCHANGE_RATES[fromCurrency] || 1;
    const toRate = EXCHANGE_RATES[toCurrency] || 1;
    setResult((val / fromRate) * toRate);
  };

  useEffect(() => {
    handleConvert();
  }, [amount, fromCurrency, toCurrency]);

  return (
    <div className="mt-6 bg-white dark:bg-slate-950 rounded-xl border border-slate-200 dark:border-slate-800 overflow-hidden shadow-sm">
      <div className="bg-slate-50 dark:bg-slate-900 px-4 py-3 border-b border-slate-100 dark:border-slate-800 flex items-center gap-2">
        <Calculator className="w-4 h-4 text-emerald-600 dark:text-emerald-400" />
        <h3 className="font-bold text-slate-800 dark:text-slate-200 text-sm">محول العملات (لتقدير التكلفة)</h3>
      </div>
      <div className="p-4 grid grid-cols-1 sm:grid-cols-[1fr_auto_1fr] gap-3 items-end" dir="ltr">
        <div className="flex flex-col gap-1">
          <div className="flex rounded-lg shadow-sm">
             <input
              type="number"
              value={amount}
              onChange={(e) => setAmount(e.target.value)}
              className="block w-full rounded-l-lg border-gray-300 dark:border-slate-700 bg-white dark:bg-slate-900 py-2 pl-3 pr-2 text-sm border text-slate-900 dark:text-white"
            />
            <select
              value={fromCurrency}
              onChange={(e) => setFromCurrency(e.target.value)}
              className="rounded-r-lg border border-l-0 border-gray-300 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 py-2 pl-2 text-sm font-semibold text-slate-900 dark:text-white"
            >
              {currencyOptions.map(c => <option key={c} value={c}>{c}</option>)}
            </select>
          </div>
        </div>
        <div className="flex items-center justify-center pb-2 text-slate-400"><RefreshCw className="w-4 h-4" /></div>
        <div className="flex flex-col gap-1">
          <div className="flex items-center justify-between rounded-lg border border-emerald-100 dark:border-emerald-900 bg-emerald-50/50 dark:bg-emerald-900/10 py-2 px-3 h-[38px]">
             <span className="font-bold text-emerald-700 dark:text-emerald-400">{result !== null ? result.toLocaleString(undefined, { maximumFractionDigits: 2 }) : '---'}</span>
             <span className="text-xs font-bold text-emerald-600 dark:text-emerald-500">{toCurrency}</span>
          </div>
        </div>
      </div>
    </div>
  );
}

const BankStatementAnalyzer: React.FC = () => {
  const [data, setData] = useState(
    Array.from({ length: 6 }).map((_, i) => ({ 
      month: `شهر ${i + 1}`, 
      credit: 0, 
      debit: 0 
    }))
  );

  const updateVal = (index: number, field: 'credit' | 'debit', val: string) => {
    const newData = [...data];
    newData[index][field] = parseFloat(val) || 0;
    setData(newData);
  };

  const totalCredit = data.reduce((acc, cur) => acc + cur.credit, 0);
  const totalDebit = data.reduce((acc, cur) => acc + cur.debit, 0);
  const netIncome = totalCredit - totalDebit;
  const avgDisposable = netIncome / 6;
  const savingsRatio = totalCredit > 0 ? (netIncome / totalCredit) * 100 : 0;

  const getRiskAssessment = () => {
    if (netIncome < 0) return { status: 'خطر مرتفع', color: 'text-red-600', bg: 'bg-red-100 dark:bg-red-900/30', icon: AlertTriangle, msg: 'المصروفات أعلى من الدخل. هذا مؤشر سلبي قوي للسفارة.' };
    if (savingsRatio < 10) return { status: 'حذر', color: 'text-amber-600', bg: 'bg-amber-100 dark:bg-amber-900/30', icon: AlertCircle, msg: 'نسبة الادخار منخفضة. يفضل دعم الحساب بمصدر دخل إضافي.' };
    return { status: 'جيد جداً', color: 'text-emerald-600', bg: 'bg-emerald-100 dark:bg-emerald-900/30', icon: CheckCircle2, msg: 'التدفق المالي يبدو مستقراً ومناسباً لتغطية نفقات السفر.' };
  };

  const assessment = getRiskAssessment();

  return (
    <div className="mt-8 bg-white dark:bg-slate-950 rounded-xl border border-slate-200 dark:border-slate-800 overflow-hidden shadow-sm">
      <div className="bg-slate-50 dark:bg-slate-900 px-4 py-3 border-b border-slate-100 dark:border-slate-800 flex items-center gap-2">
        <Landmark className="w-4 h-4 text-indigo-600 dark:text-indigo-400" />
        <h3 className="font-bold text-slate-800 dark:text-slate-200 text-sm">🇬🇧 محلل كشف الحساب (معايير بريطانيا)</h3>
      </div>

      <div className="p-4">
        <div className="text-xs text-slate-500 dark:text-slate-400 mb-4 bg-indigo-50 dark:bg-indigo-900/20 p-3 rounded border border-indigo-100 dark:border-indigo-800">
          <Info className="w-3 h-3 inline ml-1" /> 
          أدخل مجموع الإيداعات (الراتب/التحويلات) ومجموع السحوبات (المصاريف) لكل شهر من الـ 6 أشهر الأخيرة لتقييم الملاءة المالية.
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-sm text-right">
            <thead className="bg-slate-50 dark:bg-slate-900 text-slate-500 dark:text-slate-400">
              <tr>
                <th className="p-2 rounded-r-lg">الشهر</th>
                <th className="p-2 text-emerald-600 dark:text-emerald-400">إيداع (In)</th>
                <th className="p-2 text-red-600 dark:text-red-400 rounded-l-lg">سحب (Out)</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
              {data.map((row, idx) => (
                <tr key={idx}>
                  <td className="p-2 font-medium text-slate-700 dark:text-slate-300">{row.month}</td>
                  <td className="p-2">
                    <input 
                      type="number" 
                      className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded px-2 py-1 focus:ring-1 focus:ring-emerald-500 outline-none"
                      placeholder="0.00"
                      onChange={(e) => updateVal(idx, 'credit', e.target.value)}
                    />
                  </td>
                  <td className="p-2">
                    <input 
                      type="number" 
                      className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded px-2 py-1 focus:ring-1 focus:ring-red-500 outline-none"
                      placeholder="0.00"
                      onChange={(e) => updateVal(idx, 'debit', e.target.value)}
                    />
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        {/* Analysis Result */}
        <div className="mt-6 grid grid-cols-1 md:grid-cols-2 gap-4">
          <div className="bg-slate-50 dark:bg-slate-900 p-4 rounded-lg border border-slate-100 dark:border-slate-800">
             <h4 className="text-xs font-bold text-slate-500 mb-3 flex items-center gap-1"><PieChart className="w-3 h-3" /> ملخص 6 شهور</h4>
             <div className="space-y-2 text-sm">
               <div className="flex justify-between">
                 <span>إجمالي الدخل:</span>
                 <span className="font-mono font-bold text-emerald-600">{totalCredit.toLocaleString()}</span>
               </div>
               <div className="flex justify-between">
                 <span>إجمالي المصروفات:</span>
                 <span className="font-mono font-bold text-red-600">{totalDebit.toLocaleString()}</span>
               </div>
               <div className="flex justify-between pt-2 border-t border-slate-200 dark:border-slate-700">
                 <span>صافي الدخل (Disposable):</span>
                 <span className={`font-mono font-bold ${netIncome >= 0 ? 'text-indigo-600' : 'text-red-600'}`}>{netIncome.toLocaleString()}</span>
               </div>
             </div>
          </div>

          <div className={`p-4 rounded-lg border flex flex-col justify-center ${assessment.bg} border-transparent`}>
             <div className="flex items-center gap-2 mb-2">
                <assessment.icon className={`w-5 h-5 ${assessment.color}`} />
                <h4 className={`font-bold ${assessment.color}`}>تقييم الملاءة: {assessment.status}</h4>
             </div>
             <p className="text-xs text-slate-700 dark:text-slate-300 opacity-90 leading-relaxed">
               {assessment.msg}
             </p>
             {netIncome > 0 && (
                <div className="mt-3 text-xs font-medium text-slate-600 dark:text-slate-400">
                  متوسط الفائض الشهري: <span className="font-bold text-slate-900 dark:text-white">{avgDisposable.toLocaleString(undefined, {maximumFractionDigits: 0})}</span>
                </div>
             )}
          </div>
        </div>
      </div>
    </div>
  );
};

