const CurrencyConverter: React.FC<{ origin: Country; destination: Country }> = ({ origin, destination }) => {
  const [amount, setAmount] = useState<number | string>(100);
  const [fromCurrency, setFromCurrency] = useState(destination.currencyCode || 'USD');
  const [toCurrency, setToCurrency] = useState(origin.currencyCode || 'SAR');
  const [result, setResult] = useState<number | null>(null);

  const currencyOptions = Array.from(new Set(['USD', 'EUR', origin.currencyCode, destination.currencyCode].filter(Boolean)));

  const handleConvert = () => {
    const val = parseFloat(amount.toString());
    if (isNaN(val)) {
      setResult(null);
      return;
    }
    const fromRate = EXCHANGE_RATES[fromCurrency] || 1;
    const toRate = EXCHANGE_RATES[toCurrency] || 1;
    setResult((val / fromRate) * toRate);
  };

  useEffect(() => {
    handleConvert();
  }, [amount, fromCurrency, toCurrency]);

  return (
    <div className="mt-6 bg-white dark:bg-slate-950 rounded-xl border border-slate-200 dark:border-slate-800 overflow-hidden shadow-sm">
      <div className="bg-slate-50 dark:bg-slate-900 px-4 py-3 border-b border-slate-100 dark:border-slate-800 flex items-center gap-2">
        <Calculator className="w-4 h-4 text-emerald-600 dark:text-emerald-400" />
        <h3 className="font-bold text-slate-800 dark:text-slate-200 text-sm">محول العملات (لتقدير التكلفة)</h3>
      </div>
      <div className="p-4 grid grid-cols-1 sm:grid-cols-[1fr_auto_1fr] gap-3 items-end" dir="ltr">
        <div className="flex flex-col gap-1">
          <div className="flex rounded-lg shadow-sm">
             <input
              type="number"
              value={amount}
              onChange={(e) => setAmount(e.target.value)}
              className="block w-full rounded-l-lg border-gray-300 dark:border-slate-700 bg-white dark:bg-slate-900 py-2 pl-3 pr-2 text-sm border text-slate-900 dark:text-white"
            />
            <select
              value={fromCurrency}
              onChange={(e) => setFromCurrency(e.target.value)}
              className="rounded-r-lg border border-l-0 border-gray-300 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 py-2 pl-2 text-sm font-semibold text-slate-900 dark:text-white"
            >
              {currencyOptions.map(c => <option key={c} value={c}>{c}</option>)}
            </select>
          </div>
        </div>
        <div className="flex items-center justify-center pb-2 text-slate-400"><RefreshCw className="w-4 h-4" /></div>
        <div className="flex flex-col gap-1">
          <div className="flex items-center justify-between rounded-lg border border-emerald-100 dark:border-emerald-900 bg-emerald-50/50 dark:bg-emerald-900/10 py-2 px-3 h-[38px]">
             <span className="font-bold text-emerald-700 dark:text-emerald-400">{result !== null ? result.toLocaleString(undefined, { maximumFractionDigits: 2 }) : '---'}</span>
             <span className="text-xs font-bold text-emerald-600 dark:text-emerald-500">{toCurrency}</span>
          </div>
        </div>
      </div>
    </div>
  );
}

const BankStatementAnalyzer: React.FC = () => {
  const [data, setData] = useState(
    Array.from({ length: 6 }).map((_, i) => ({ 
      month: `شهر ${i + 1}`, 
      credit: 0, 
      debit: 0 
    }))
  );

  const updateVal = (index: number, field: 'credit' | 'debit', val: string) => {
    const newData = [...data];
    newData[index][field] = parseFloat(val) || 0;
    setData(newData);
  };

  const totalCredit = data.reduce((acc, cur) => acc + cur.credit, 0);
  const totalDebit = data.reduce((acc, cur) => acc + cur.debit, 0);
  const netIncome = totalCredit - totalDebit;
  const avgDisposable = netIncome / 6;
  const savingsRatio = totalCredit > 0 ? (netIncome / totalCredit) * 100 : 0;

  const getRiskAssessment = () => {
    if (netIncome < 0) return { status: 'خطر مرتفع', color: 'text-red-600', bg: 'bg-red-100 dark:bg-red-900/30', icon: AlertTriangle, msg: 'المصروفات أعلى من الدخل. هذا مؤشر سلبي قوي للسفارة.' };
    if (savingsRatio < 10) return { status: 'حذر', color: 'text-amber-600', bg: 'bg-amber-100 dark:bg-amber-900/30', icon: AlertCircle, msg: 'نسبة الادخار منخفضة. يفضل دعم الحساب بمصدر دخل إضافي.' };
    return { status: 'جيد جداً', color: 'text-emerald-600', bg: 'bg-emerald-100 dark:bg-emerald-900/30', icon: CheckCircle2, msg: 'التدفق المالي يبدو مستقراً ومناسباً لتغطية نفقات السفر.' };
  };

  const assessment = getRiskAssessment();

  return (
    <div className="mt-8 bg-white dark:bg-slate-950 rounded-xl border border-slate-200 dark:border-slate-800 overflow-hidden shadow-sm">
      <div className="bg-slate-50 dark:bg-slate-900 px-4 py-3 border-b border-slate-100 dark:border-slate-800 flex items-center gap-2">
        <Landmark className="w-4 h-4 text-indigo-600 dark:text-indigo-400" />
        <h3 className="font-bold text-slate-800 dark:text-slate-200 text-sm">🇬🇧 محلل كشف الحساب (معايير بريطانيا)</h3>
      </div>

      <div className="p-4">
        <div className="text-xs text-slate-500 dark:text-slate-400 mb-4 bg-indigo-50 dark:bg-indigo-900/20 p-3 rounded border border-indigo-100 dark:border-indigo-800">
          <Info className="w-3 h-3 inline ml-1" /> 
          أدخل مجموع الإيداعات (الراتب/التحويلات) ومجموع السحوبات (المصاريف) لكل شهر من الـ 6 أشهر الأخيرة لتقييم الملاءة المالية.
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-sm text-right">
            <thead className="bg-slate-50 dark:bg-slate-900 text-slate-500 dark:text-slate-400">
              <tr>
                <th className="p-2 rounded-r-lg">الشهر</th>
                <th className="p-2 text-emerald-600 dark:text-emerald-400">إيداع (In)</th>
                <th className="p-2 text-red-600 dark:text-red-400 rounded-l-lg">سحب (Out)</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
              {data.map((row, idx) => (
                <tr key={idx}>
                  <td className="p-2 font-medium text-slate-700 dark:text-slate-300">{row.month}</td>
                  <td className="p-2">
                    <input 
                      type="number" 
                      className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded px-2 py-1 focus:ring-1 focus:ring-emerald-500 outline-none"
                      placeholder="0.00"
                      onChange={(e) => updateVal(idx, 'credit', e.target.value)}
                    />
                  </td>
                  <td className="p-2">
                    <input 
                      type="number" 
                      className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded px-2 py-1 focus:ring-1 focus:ring-red-500 outline-none"
                      placeholder="0.00"
                      onChange={(e) => updateVal(idx, 'debit', e.target.value)}
                    />
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        {/* Analysis Result */}
        <div className="mt-6 grid grid-cols-1 md:grid-cols-2 gap-4">
          <div className="bg-slate-50 dark:bg-slate-900 p-4 rounded-lg border border-slate-100 dark:border-slate-800">
             <h4 className="text-xs font-bold text-slate-500 mb-3 flex items-center gap-1"><PieChart className="w-3 h-3" /> ملخص 6 شهور</h4>
             <div className="space-y-2 text-sm">
               <div className="flex justify-between">
                 <span>إجمالي الدخل:</span>
                 <span className="font-mono font-bold text-emerald-600">{totalCredit.toLocaleString()}</span>
               </div>
               <div className="flex justify-between">
                 <span>إجمالي المصروفات:</span>
                 <span className="font-mono font-bold text-red-600">{totalDebit.toLocaleString()}</span>
               </div>
               <div className="flex justify-between pt-2 border-t border-slate-200 dark:border-slate-700">
                 <span>صافي الدخل (Disposable):</span>
                 <span className={`font-mono font-bold ${netIncome >= 0 ? 'text-indigo-600' : 'text-red-600'}`}>{netIncome.toLocaleString()}</span>
               </div>
             </div>
          </div>

          <div className={`p-4 rounded-lg border flex flex-col justify-center ${assessment.bg} border-transparent`}>
             <div className="flex items-center gap-2 mb-2">
                <assessment.icon className={`w-5 h-5 ${assessment.color}`} />
                <h4 className={`font-bold ${assessment.color}`}>تقييم الملاءة: {assessment.status}</h4>
             </div>
             <p className="text-xs text-slate-700 dark:text-slate-300 opacity-90 leading-relaxed">
               {assessment.msg}
             </p>
             {netIncome > 0 && (
                <div className="mt-3 text-xs font-medium text-slate-600 dark:text-slate-400">
                  متوسط الفائض الشهري: <span className="font-bold text-slate-900 dark:text-white">{avgDisposable.toLocaleString(undefined, {maximumFractionDigits: 0})}</span>
                </div>
             )}
          </div>
        </div>
      </div>
    </div>
  );
};

