        return (
            <div className="flex items-center gap-2 mt-8 mb-4 text-lg font-bold text-blue-700 dark:text-blue-400 border-r-4 border-blue-500 pr-3 bg-blue-50 dark:bg-blue-900/10 py-2 rounded-l-md">
                <FileText className="w-6 h-6" />
                <h2 {...props} />
            </div>
        )
    }
    if (text.includes('رفض') || text.includes('Red Flags') || text.includes('تحذير')) {
