const CurrencyConverter: React.FC<{ origin: Country; destination: Country }> = ({ origin, destination }) => {
  const [amount, setAmount] = useState<number | string>(100);
  const [fromCurrency, setFromCurrency] = useState(destination.currencyCode || 'USD');
  const [toCurrency, setToCurrency] = useState(origin.currencyCode || 'SAR');
  const [result, setResult] = useState<number | null>(null);

  const currencyOptions = Array.from(new Set(['USD', 'EUR', origin.currencyCode, destination.currencyCode].filter(Boolean)));

  const handleConvert = () => {
    const val = parseFloat(amount.toString());
    if (isNaN(val)) {
      setResult(null);
      return;
    }
    const fromRate = EXCHANGE_RATES[fromCurrency] || 1;
    const toRate = EXCHANGE_RATES[toCurrency] || 1;
    setResult((val / fromRate) * toRate);
  };

  useEffect(() => {
    handleConvert();
  }, [amount, fromCurrency, toCurrency]);

  return (
    <div className="mt-6 bg-white dark:bg-slate-950 rounded-xl border border-slate-200 dark:border-slate-800 overflow-hidden shadow-sm">
      <div className="bg-slate-50 dark:bg-slate-900 px-4 py-3 border-b border-slate-100 dark:border-slate-800 flex items-center gap-2">
        <Calculator className="w-4 h-4 text-emerald-600 dark:text-emerald-400" />
        <h3 className="font-bold text-slate-800 dark:text-slate-200 text-sm">محول العملات (لتقدير التكلفة)</h3>
      </div>
      <div className="p-4 grid grid-cols-1 sm:grid-cols-[1fr_auto_1fr] gap-3 items-end" dir="ltr">
        <div className="flex flex-col gap-1">
          <div className="flex rounded-lg shadow-sm">
             <input
              type="number"
              value={amount}
              onChange={(e) => setAmount(e.target.value)}
              className="block w-full rounded-l-lg border-gray-300 dark:border-slate-700 bg-white dark:bg-slate-900 py-2 pl-3 pr-2 text-sm border text-slate-900 dark:text-white"
            />
            <select
              value={fromCurrency}
              onChange={(e) => setFromCurrency(e.target.value)}
