// --- CONSTANTS & TEMPLATES ---

const CANADA_VISA_EXEMPTIONS = `
**⚡ ملاحظة هامة: إعفاءات حاملي التأشيرة الكندية الصالحة**
إذا كان المتقدم يحمل تأشيرة **كندية** صالحة ومستخدمة (أو متعددة الدخول)، يرجى إدراج قاعدة الإعفاء المحددة لهذه الوجهة:
`;

// --- RULES DICTIONARY ---
const VISA_RULES: Record<string, string> = {
  'MX': `${CANADA_VISA_EXEMPTIONS} - المكسيك: يسمح بالدخول بدون تأشيرة لحاملي التأشيرة الكندية أو الأمريكية أو الشنغن.`,
  'TR': `
    **🚨 قواعد حرجة لتأشيرة تركيا (تحديث 2024/2025):**
    1. التأشيرة الإلكترونية متاحة لمن هم دون الـ 20 أو فوق الـ 45 عاماً (للمصريين).
    2. الفئة العمرية الوسطى (20-45) تتطلب ملصق (Sticker) من السفارة أو تأشيرة شنغن/أمريكا صالحة للحصول على الإلكترونية.
    3. التأمين الصحي التركي إلزامي ويجب إصداره من المكتب المعتمد.
  `,
  'GB': `
    **🚨 قواعد التأشيرة البريطانية (UKVI):**
    1. كشف الحساب البنكي لآخر 6 أشهر أساسي.
    2. سياسة Appendix V 4.2 صارمة جداً بشأن "تراكم الأموال" (Funds Parking).
    3. لا توجد مقابلة شخصية في الغالب، القرار يعتمد على جودة المستندات.
  `,
  'US': `
    **🚨 قواعد التأشيرة الأمريكية:**
    1. نموذج DS-160 هو المستند الأهم.
    2. المقابلة الشخصية إلزامية لجميع الفئات حالياً في معظم القنصليات العربية.
    3. دفع الرسوم يتم عبر البنك التجاري الدولي (CIB) في مصر أو ما يعادله.
  `,
  'FR': `
    **🚨 فرنسا (TLS Contact):**
    1. حجز المواعيد يتطلب دفع رسوم الخدمة مسبقاً.
    2. يجب ملء الأبليكشن على موقع France-Visas أولاً.
  `
};

export const getVisaRequirements = async (params: VisaRequestParams): Promise<VisaInfoResponse> => {
  try {
    const today = new Date().toLocaleDateString('ar-EG', { year: 'numeric', month: 'long', day: 'numeric' });
    const destCode = params.destination.code;
    const specialInstructions = VISA_RULES[destCode] || "";

    const prompt = `
      **ROLE**: SENIOR VISA COMPLIANCE OFFICER.
      **TASK**: Generate a professional visa requirement report based on CURRENT embassy regulations for 2024/2025.

      **CONTEXT**:
      - Applicant: ${params.origin.nameEn} (${params.origin.nameAr})
      - Destination: ${params.destination.nameEn} (${params.destination.nameAr})
      - Date: ${today}

      ${specialInstructions}

      **STRICT INSTRUCTIONS**:
      1. Use Google Search to find the LATEST fees, processing times, and document lists from official government sites (MFA, VFS Global, TLSContact, BLS).
      2. Format in professional Arabic Markdown.
      3. Clearly state if a visa is required, E-visa, or Visa on Arrival.
      4. List exact fees in the original currency (e.g., EUR/USD) and the local currency of the applicant's origin if possible.

      **OUTPUT STRUCTURE**:
      # 🏛️ تقرير متطلبات التأشيرة الرسمي
      ## 1. الحالة والنوع (Visa Status)
      ## 2. 💰 الرسوم التفصيلية (Current Fees)
      ## 3. 📂 المستندات المطلوبة (Required Documents)
      ## 4. ⏳ المواعيد والمدة (Timeline)
      ## 5. 🚨 تنبيهات الرفض (Critical Warnings)
      ## 6. 🔗 روابط التقديم الرسمية
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
      },
    });

    const markdown = response.text || "لم يتم العثور على بيانات.";

    // Extract search grounding sources
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    const sources = groundingChunks
      ?.filter((chunk: any) => chunk.web?.uri && chunk.web?.title)
      .map((chunk: any) => ({
        title: chunk.web!.title,
        url: chunk.web!.uri
      })) || [];

    return {
      markdown,
      sources: Array.from(new Map(sources.map((s: any) => [s.url, s])).values()) as any,
      generatedAt: new Date().toISOString()
    };

  } catch (error: any) {
    console.error("Gemini API Error:", error);
    throw new Error(error.message || "فشل في جلب البيانات من السفارة.");
  }
};

export interface BankAnalysisResult {
  months: { month: string; credit: number; debit: number; lowestBalance?: number }[];
  salaryEstimation: number;
  warnings: string[];
}

export const analyzeBankStatement = async (fileBase64: string, mimeType: string): Promise<BankAnalysisResult> => {
  try {
    const prompt = `Analyze this bank statement for a UK/Schengen visa. Extract 6 months of credits, debits, and lowest balances. Identify funds parking or low sustainability. Return JSON only.`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: {
        parts: [
          { text: prompt },
          { inlineData: { mimeType, data: fileBase64 } }
        ]
      },
      config: {
        responseMimeType: 'application/json',
      }
    });

    return JSON.parse(response.text || "{}");
  } catch (error) {
    console.error("Analysis failed:", error);
    throw error;
  }
};

