const extractTextFromNode = (node: any): string => {
  if (!node) return '';
  if (typeof node === 'string') return node;
  if (Array.isArray(node)) return node.map(extractTextFromNode).join('');
  if (typeof node === 'object' && node.props && node.props.children) {
    return extractTextFromNode(node.props.children);
  }
  return '';
};

const getSectionConfig = (text: string) => {
  if (text.includes('رسوم') || text.includes('Fees')) return { type: 'fees', color: 'text-emerald-700 dark:text-emerald-400', border: 'border-emerald-500', bg: 'bg-emerald-50 dark:bg-emerald-900/10' };
  if (text.includes('مستندات') || text.includes('Documents')) return { type: 'docs', color: 'text-blue-700 dark:text-blue-400', border: 'border-blue-500', bg: 'bg-blue-50 dark:bg-blue-900/10' };
  if (text.includes('رفض') || text.includes('Red Flags')) return { type: 'alert', color: 'text-red-700 dark:text-red-400', border: 'border-red-500', bg: 'bg-red-50 dark:bg-red-900/10' };
  return null;
};

const IconManager = ({ type, className = "w-6 h-6" }: { type: string, className?: string }) => {
  switch (type) {
    case 'fees': return <Calculator className={className} />;
    case 'docs': return <FileText className={className} />;
    case 'alert': return <AlertTriangle className={className} />;
    default: return null;
