}

export const analyzeBankStatement = async (fileBase64: string, mimeType: string): Promise<BankAnalysisResult> => {
  try {
    const prompt = `Analyze this bank statement for a UK/Schengen visa. Extract 6 months of credits, debits, and lowest balances. Identify funds parking or low sustainability. Return JSON only.`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: {
        parts: [
          { text: prompt },
          { inlineData: { mimeType, data: fileBase64 } }
        ]
      },
      config: {
        responseMimeType: 'application/json',
      }
    });

    return JSON.parse(response.text || "{}");
  } catch (error) {
    console.error("Analysis failed:", error);
    throw error;
  }
};

