      return {
        title: "خطأ في التصريح",
        icon: <Lock className="w-6 h-6 text-rose-600 shrink-0" />,
        className: "bg-rose-50 border-rose-100 text-rose-900 dark:bg-rose-900/20 dark:border-rose-800 dark:text-rose-200"
      };
    }

    // Server / Quota Errors
