          <h2 {...props} />
        </div>
      );
    }
    return <h2 className="text-xl font-bold text-slate-800 dark:text-slate-200 mt-8 mb-4" {...props} />;
  },
  p: ({ ...props }) => <p className="text-slate-600 dark:text-slate-300 leading-relaxed mb-4 text-sm md:text-base" {...props} />,
  ul: ({ ...props }) => <ul className="list-disc list-inside space-y-2 mb-4 text-slate-600 dark:text-slate-300 bg-white dark:bg-slate-900 p-4 rounded-xl border border-slate-200 dark:border-slate-700 shadow-sm" {...props} />,
};

const CurrencyConverter: React.FC<{ origin: Country; destination: Country }> = ({ origin, destination }) => {
  const [amount, setAmount] = useState<number | string>(100);
  const [fromCurrency, setFromCurrency] = useState(destination.currencyCode || 'USD');
  const [toCurrency, setToCurrency] = useState('USD');
  const [result, setResult] = useState<number | null>(null);

  const currencyOptions = useMemo(() => {
    return Array.from(new Set(['USD', 'EUR', origin.currencyCode, destination.currencyCode].filter(Boolean))) as string[];
  }, [origin, destination]);

  const handleConvert = () => {
    const val = parseFloat(amount.toString());
    if (isNaN(val)) {
      setResult(null);
      return;
    }
    const fromRate = EXCHANGE_RATES[fromCurrency] || 1;
    const toRate = EXCHANGE_RATES[toCurrency] || 1;
    setResult((val / fromRate) * toRate);
  };

  useEffect(() => {
    handleConvert();
  }, [amount, fromCurrency, toCurrency]);

  const swapCurrencies = () => {
    const temp = fromCurrency;
    setFromCurrency(toCurrency);
    setToCurrency(temp);
  };

  return (
    <div className="mt-8 bg-white dark:bg-slate-950 rounded-2xl border border-slate-200 dark:border-slate-800 overflow-hidden shadow-sm">
      <div className="bg-slate-50 dark:bg-slate-900 px-5 py-4 border-b border-slate-100 dark:border-slate-800 flex flex-col sm:flex-row items-start sm:items-center justify-between gap-3">
        <div className="flex items-center gap-2">
            <IconManager type="currency" className="w-5 h-5 text-emerald-600 dark:text-emerald-400" />
            <h3 className="font-bold text-slate-800 dark:text-slate-200 text-sm">محول عملات التكاليف</h3>
        </div>
        <div className="flex items-center gap-2 bg-slate-200/50 dark:bg-slate-800 p-1 rounded-lg">
           <button 
             onClick={() => setToCurrency('USD')}
             className={`text-[11px] px-3 py-1.5 rounded-md font-bold transition-all ${toCurrency === 'USD' ? 'bg-white dark:bg-slate-700 text-emerald-600 dark:text-emerald-400 shadow-sm' : 'text-slate-500'}`}
           >
             USD ($)
           </button>
           {origin.currencyCode && origin.currencyCode !== 'USD' && (
             <button 
                onClick={() => setToCurrency(origin.currencyCode)}
                className={`text-[11px] px-3 py-1.5 rounded-md font-bold transition-all ${toCurrency === origin.currencyCode ? 'bg-white dark:bg-slate-700 text-emerald-600 dark:text-emerald-400 shadow-sm' : 'text-slate-500'}`}
             >
                {origin.currencyCode} (المحلية)
             </button>
           )}
        </div>
      </div>
      <div className="p-6 grid grid-cols-1 sm:grid-cols-[1fr_auto_1fr] gap-4 items-center" dir="ltr">

        <div className="space-y-2">
          <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">قيمة الرسوم</label>
          <div className="flex rounded-xl overflow-hidden border border-slate-200 dark:border-slate-700 focus-within:ring-2 focus-within:ring-emerald-500/20 focus-within:border-emerald-500 transition-all">
             <input
              type="number"
              value={amount}
              onChange={(e) => setAmount(e.target.value)}
              className="block w-full bg-white dark:bg-slate-900 py-3 px-4 text-base text-slate-900 dark:text-white outline-none"
            />
            <select
              value={fromCurrency}
              onChange={(e) => setFromCurrency(e.target.value)}
              className="bg-slate-100 dark:bg-slate-800 py-3 px-3 text-sm font-bold text-slate-700 dark:text-slate-200 border-l border-slate-200 dark:border-slate-700 outline-none cursor-pointer"
            >
              {currencyOptions.map(c => <option key={c} value={c}>{c}</option>)}
            </select>
          </div>
        </div>

        <div className="flex items-center justify-center pt-6 sm:pt-4">
             <button onClick={swapCurrencies} className="p-2.5 rounded-full bg-slate-100 dark:bg-slate-800 text-slate-400 hover:text-emerald-600 dark:hover:text-emerald-400 hover:bg-emerald-50 dark:hover:bg-emerald-900/20 transition-all active:scale-95">
                <IconManager type="swap" className="w-5 h-5" />
             </button>
        </div>

        <div className="space-y-2">
          <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">ستدفع تقريباً</label>
          <div className="flex rounded-xl overflow-hidden border border-emerald-200 dark:border-emerald-800/50 bg-emerald-50/30 dark:bg-emerald-900/5">
            <div className="block w-full py-3 px-4 text-lg text-emerald-700 dark:text-emerald-400 font-black">
                {result !== null ? result.toLocaleString(undefined, { maximumFractionDigits: 2 }) : '---'}
            </div>
            <select
              value={toCurrency}
              onChange={(e) => setToCurrency(e.target.value)}
              className="bg-emerald-100 dark:bg-emerald-900/40 py-3 px-3 text-sm font-bold text-emerald-900 dark:text-emerald-100 border-l border-emerald-200 dark:border-emerald-800/50 outline-none cursor-pointer"
            >
               {currencyOptions.map(c => <option key={c} value={c}>{c}</option>)}
            </select>
          </div>
        </div>
      </div>
      <div className="px-6 pb-6 text-[10px] text-slate-400 italic">
        * يتم التحديث بناءً على أسعار صرف تقريبية لغرض التخطيط المالي فقط.
      </div>
    </div>
  );
}

