export const getVisaRequirements = async (params: VisaRequestParams): Promise<VisaInfoResponse> => {
  try {
    const today = new Date().toLocaleDateString('ar-EG', { year: 'numeric', month: 'long', day: 'numeric' });
    const destCode = params.destination.code;
    const specialInstructions = VISA_RULES[destCode] || "";

    const prompt = `
      **ROLE**: SENIOR VISA COMPLIANCE OFFICER.
      **TASK**: Generate a professional visa requirement report based on CURRENT embassy regulations for 2024/2025 and 2026 updates.

      **CONTEXT**:
      - Applicant: ${params.origin.nameEn} (${params.origin.nameAr})
      - Destination: ${params.destination.nameEn} (${params.destination.nameAr})
      - Date: ${today}

      ${specialInstructions}

      **STRICT INSTRUCTIONS**:
      1. Use Google Search to find the LATEST fees, processing times, and document lists from official government sites (MFA, VFS Global, TLSContact, BLS, GVCW).
      2. If destination is United Kingdom (GB), mention the transition to eVisas.
      3. If destination is Greece (GR), EXPLICITLY mention the jurisdiction rules based on passport issue numbers (18, 19, 20, 21, 36, 37 for Alex, others for Cairo).
      4. If destination is Turkey (TR), mention that employment proof from outside Egypt is accepted under the specified conditions.
      5. If destination is Canada (CA), pay special attention to eTA eligibility for holders of valid US visas or those with recent Canadian visa history, and mention the impact of holding Schengen/UK visas.
      6. Format in professional Arabic Markdown.
      7. Clearly state if a visa is required, E-visa, or Visa on Arrival.
      8. List exact fees in the original currency (e.g., EUR/USD) and the local currency of the applicant's origin if possible.

      **OUTPUT STRUCTURE**:
      # 🏛️ تقرير متطلبات التأشيرة الرسمي
      ## 1. الحالة والنوع (Visa Status)
      ## 2. 💰 الرسوم التفصيلية (Current Fees)
      ## 3. 📂 المستندات المطلوبة (Required Documents)
      ## 4. ⏳ المواعيد والمدة (Timeline)
      ## 5. 🚨 تنبيهات الرفض (Critical Warnings)
      ## 6. 🔗 روابط التقديم الرسمية
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
      },
    });

    const markdown = response.text || "لم يتم العثور على بيانات.";

    // Extract search grounding sources
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    const sources = groundingChunks
      ?.filter((chunk: any) => chunk.web?.uri && chunk.web?.title)
      .map((chunk: any) => ({
        title: chunk.web!.title,
        url: chunk.web!.uri
      })) || [];

    return {
      markdown,
      sources: Array.from(new Map(sources.map((s: any) => [s.url, s])).values()) as any,
      generatedAt: new Date().toISOString()
    };

  } catch (error: any) {
    console.error("Gemini API Error:", error);
    throw new Error(error.message || "فشل في جلب البيانات من السفارة.");
  }
};

