interface CountryComboboxProps {
  label: string;
  countries: Country[];
  selectedCountry: Country | null;
  onSelect: (country: Country) => void;
  placeholder?: string;
}

// --- Fuzzy Search Helpers ---

const normalizeText = (text: string): string => {
  return text
    .toLowerCase()
    .replace(/[أإآ]/g, 'ا')
    .replace(/ة/g, 'ه')
    .replace(/ى/g, 'ي')
    .replace(/ؤ/g, 'و')
    .replace(/ئ/g, 'ي')
    .replace(/[^\w\s\u0600-\u06FF]/g, '')
    .trim();
};

const levenshteinDistance = (a: string, b: string): number => {
  if (a.length === 0) return b.length;
  if (b.length === 0) return a.length;

  const matrix = Array(b.length + 1).fill(null).map(() => Array(a.length + 1).fill(null));

  for (let i = 0; i <= b.length; i++) matrix[i][0] = i;
  for (let j = 0; j <= a.length; j++) matrix[0][j] = j;

  for (let i = 1; i <= b.length; i++) {
    for (let j = 1; j <= a.length; j++) {
      const cost = a[j - 1] === b[i - 1] ? 0 : 1;
      matrix[i][j] = Math.min(
        matrix[i - 1][j] + 1, // deletion
        matrix[i][j - 1] + 1, // insertion
        matrix[i - 1][j - 1] + cost // substitution
      );
    }
  }

  return matrix[b.length][a.length];
};

const CountryCombobox: React.FC<CountryComboboxProps> = ({
  label,
  countries,
  selectedCountry,
  onSelect,
  placeholder = "اختر دولة..."
}) => {
  const [isOpen, setIsOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [debouncedQuery, setDebouncedQuery] = useState('');
  const wrapperRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  const uniqueId = useId();
  const labelId = `label-${uniqueId}`;
  const listboxId = `listbox-${uniqueId}`;

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (wrapperRef.current && !wrapperRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  useEffect(() => {
    if (isOpen && inputRef.current) {
      setTimeout(() => {
        inputRef.current?.focus();
      }, 50);
    }
  }, [isOpen]);

  useEffect(() => {
    const timer = setTimeout(() => {
      setDebouncedQuery(searchQuery);
    }, 300);

    return () => clearTimeout(timer);
  }, [searchQuery]);

  // Pre-compute normalized country names for performance
  const searchableCountries = useMemo(() => {
    return countries.map(country => ({
      ...country,
      normAr: normalizeText(country.nameAr),
      normEn: normalizeText(country.nameEn)
    }));
  }, [countries]);

  // Enhanced Fuzzy Search Logic
  const filteredCountries = useMemo(() => {
    const query = normalizeText(debouncedQuery);

    if (!query) return countries;

    return searchableCountries
      .map(item => {
        const { normAr, normEn, ...country } = item;
        let score = 999;
        let match = false;

        if (normAr === query || normEn === query) {
            score = 0;
            match = true;
        }
        else if (normAr.startsWith(query) || normEn.startsWith(query)) {
            score = 10;
            match = true;
        }
        else if (normAr.includes(query) || normEn.includes(query)) {
             score = 20;
             match = true;
        }
        else if (query.length >= 2) {
            const distAr = levenshteinDistance(query, normAr);
            const distEn = levenshteinDistance(query, normEn);
            const threshold = Math.floor(query.length * 0.4) + 1; 

            if (distAr <= threshold || distEn <= threshold) {
                 score = 30 + Math.min(distAr, distEn);
                 match = true;
            } else {
                const words = [...normAr.split(' '), ...normEn.split(' ')];
                let bestWordDist = 100;

                for (const word of words) {
                    if (Math.abs(word.length - query.length) > 2) continue;
                    const d = levenshteinDistance(query, word);
                    if (d < bestWordDist) bestWordDist = d;
                }

                if (bestWordDist <= 1) { 
                    score = 40 + bestWordDist;
                    match = true;
                }
            }
        }

        return { country, score, match };
      })
      .filter(item => item.match)
      .sort((a, b) => a.score - b.score)
      .map(item => item.country);

  }, [debouncedQuery, searchableCountries, countries]);

  const handleSelect = (country: Country) => {
    onSelect(country);
    setIsOpen(false);
    setSearchQuery('');
    setDebouncedQuery('');
  };

  // Advanced dynamic styles using the country's color
  const dynamicTriggerStyles = useMemo(() => {
    if (!selectedCountry) return {};
    const color = selectedCountry.color;
    return {
      borderColor: color,
      boxShadow: isOpen 
        ? `0 0 0 4px ${color}20` 
        : `0 4px 12px ${color}15, 0 0 0 1px ${color}20`,
      borderWidth: '2px'
    };
  }, [selectedCountry, isOpen]);

  return (
    <div className="w-full relative group" ref={wrapperRef}>
      <label 
        id={labelId}
        className={`block text-sm font-bold mb-2 transition-colors duration-300 ${selectedCountry ? 'text-slate-900 dark:text-white' : 'text-slate-500'}`}
        style={selectedCountry ? { color: selectedCountry.color } : {}}
      >
        {label}
      </label>

      <button
        type="button"
        onClick={() => setIsOpen(!isOpen)}
        aria-haspopup="listbox"
        aria-expanded={isOpen}
        aria-controls={listboxId}
        aria-labelledby={labelId}
        style={dynamicTriggerStyles}
        className={`
          w-full flex items-center justify-between 
          bg-white dark:bg-slate-900 border rounded-2xl px-4 py-3 text-right min-h-[64px]
          transition-all duration-300 ease-in-out relative z-10
          focus:outline-none focus:ring-2
          ${!selectedCountry ? 'border-slate-200 dark:border-slate-800 hover:border-emerald-400 dark:hover:border-emerald-600 shadow-sm' : ''}
          ${isOpen && !selectedCountry ? 'border-emerald-500 ring-emerald-500/20 shadow-lg shadow-emerald-500/10' : ''}
        `}
      >
        <span className={`flex items-center gap-4 ${!selectedCountry ? 'text-slate-400 dark:text-slate-500' : 'text-slate-900 dark:text-white'} text-right overflow-hidden w-full`}>
          {selectedCountry ? (
            <>
              <div 
                className="w-12 h-12 rounded-xl flex items-center justify-center shrink-0 shadow-sm transition-all duration-500 group-hover:scale-110"
                style={{ backgroundColor: `${selectedCountry.color}15`, border: `2px solid ${selectedCountry.color}30` }}
              >
                <span className="text-3xl leading-none filter drop-shadow-md" aria-hidden="true">{selectedCountry.flag}</span>
              </div>
              <div className="flex flex-col items-start overflow-hidden">
                <span className="font-black truncate w-full text-base text-slate-800 dark:text-slate-100 leading-tight">{selectedCountry.nameAr}</span>
                <span className="text-[10px] text-slate-500 dark:text-slate-400 font-bold truncate w-full uppercase tracking-widest opacity-70">{selectedCountry.nameEn}</span>
              </div>
            </>
          ) : (
            <span className="font-medium text-slate-400">{placeholder}</span>
          )}
        </span>
        <div className={`p-1.5 rounded-lg transition-all duration-300 ${isOpen ? 'bg-slate-100 dark:bg-slate-800' : ''}`}>
          <ChevronDown 
            className={`w-5 h-5 transition-transform duration-300 shrink-0 ${isOpen ? 'rotate-180 text-emerald-500' : 'text-slate-400'}`} 
            aria-hidden="true"
          />
        </div>
      </button>

      {isOpen && (
        <div 
          className="absolute z-[60] w-full mt-3 bg-white/95 dark:bg-slate-900/95 backdrop-blur-xl rounded-2xl shadow-2xl border border-slate-200 dark:border-slate-700 overflow-hidden animate-in fade-in zoom-in-95 duration-200 origin-top ring-1 ring-black/5"
        >
          <div className="p-3 border-b border-slate-100 dark:border-slate-800 sticky top-0 bg-transparent z-10">
            <div className="relative">
              <Search className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 dark:text-slate-500 pointer-events-none" aria-hidden="true" />
              <input
                ref={inputRef}
                type="text"
                className="w-full pl-10 pr-10 py-3 bg-slate-50 dark:bg-slate-800/50 rounded-xl text-sm font-bold focus:outline-none focus:ring-2 focus:ring-emerald-500/50 text-slate-900 dark:text-slate-100 placeholder:text-slate-400 dark:placeholder:text-slate-600 transition-all"
                placeholder="ابحث باسم الدولة..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                aria-label="بحث عن دولة"
                aria-autocomplete="list"
                aria-controls={listboxId}
              />
              {searchQuery && (
                <button
                  onClick={() => {
                    setSearchQuery('');
                    setDebouncedQuery('');
                    inputRef.current?.focus();
                  }}
                  className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600 dark:text-slate-500 dark:hover:text-slate-300 p-1.5 rounded-full hover:bg-slate-100 dark:hover:bg-slate-700 transition-colors"
                  type="button"
                  aria-label="مسح البحث"
                >
                  <X className="w-4 h-4" />
                </button>
              )}
            </div>
          </div>

          <ul 
            id={listboxId}
            role="listbox"
            aria-label={label}
            className="max-h-72 overflow-y-auto p-2 focus:outline-none scroll-smooth custom-scrollbar"
            tabIndex={-1}
          >
            {filteredCountries.length === 0 ? (
              <li className="p-8 text-center" role="status">
                 <div className="text-3xl mb-2 opacity-20">🌍</div>
                 <p className="text-sm text-slate-500 dark:text-slate-400 font-bold">لا توجد نتائج مطابقة</p>
              </li>
            ) : (
              filteredCountries.map((country) => {
                const isSelected = selectedCountry?.code === country.code;
                return (
                  <li 
                    key={country.code} 
                    role="presentation"
                    className="mb-1 last:mb-0"
                  >
                    <button
                      role="option"
                      aria-selected={isSelected}
                      onClick={() => handleSelect(country)}
                      className={`
                        w-full flex items-center justify-between px-3 py-2 text-right text-sm rounded-xl
                        transition-all duration-200 group/item
                        ${isSelected 
                          ? 'bg-slate-100 dark:bg-slate-800 font-black' 
                          : 'text-slate-600 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800/50'}
                      `}
                    >
                      <span className="flex items-center gap-3">
                        <div 
                          className="w-10 h-10 rounded-lg flex items-center justify-center shrink-0 border border-transparent transition-all group-hover/item:scale-110"
                          style={isSelected ? { backgroundColor: `${country.color}20`, borderColor: `${country.color}40` } : { backgroundColor: 'transparent' }}
                        >
                          <span className="text-2xl leading-none filter drop-shadow-sm" aria-hidden="true">{country.flag}</span>
                        </div>
                        <div className="flex flex-col items-start overflow-hidden">
                          <span className={`transition-colors ${isSelected ? 'text-slate-900 dark:text-white' : 'text-slate-700 dark:text-slate-300'}`} style={isSelected ? { color: country.color } : {}}>
                            {country.nameAr}
                          </span>
                          <span className="text-[9px] text-slate-400 dark:text-slate-500 uppercase tracking-widest font-bold">{country.nameEn}</span>
                        </div>
                      </span>
                      {isSelected && (
                        <div 
                          className="p-1.5 rounded-lg shadow-sm animate-in zoom-in-50"
                          style={{ backgroundColor: country.color, color: 'white' }}
                        >
                          <Check className="w-3.5 h-3.5" aria-hidden="true" />
                        </div>
                      )}
                    </button>
                  </li>
                );
              })
            )}
          </ul>
        </div>
      )}
    </div>
  );
};

