      borderWidth: '3px'
    };
  }, [selectedCountry, isOpen]);

  return (
    <div className="w-full relative group" ref={wrapperRef}>
      <label 
        id={labelId}
        className={`block text-sm font-black mb-3 transition-all duration-500 uppercase tracking-[0.2em] ${selectedCountry ? '' : 'text-slate-400 dark:text-slate-500'}`}
