            id={listboxId}
            role="listbox"
            aria-label={label}
            className="max-h-80 overflow-y-auto p-2 focus:outline-none scroll-smooth custom-scrollbar"
            tabIndex={-1}
          >
            {filteredCountries.length === 0 ? (
              <li className="p-10 text-center" role="status">
                 <div className="text-4xl mb-3 opacity-20 grayscale">🌍</div>
                 <p className="text-sm text-slate-500 dark:text-slate-400 font-bold">لم نجد هذه الدولة</p>
              </li>
            ) : (
              filteredCountries.map((country) => {
                const isSelected = selectedCountry?.code === country.code;
                return (
                  <li 
                    key={country.code} 
                    role="presentation"
                    className="mb-1 last:mb-0"
                  >
                    <button
                      role="option"
                      aria-selected={isSelected}
                      onClick={() => handleSelect(country)}
                      className={`
                        w-full flex items-center justify-between px-3 py-2 text-right text-sm rounded-2xl
                        transition-all duration-300 group/item
                        ${isSelected 
                          ? 'bg-slate-100/80 dark:bg-slate-800 font-black' 
                          : 'text-slate-600 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800/40'}
                      `}
                    >
                      <span className="flex items-center gap-4">
                        <div 
                          className="w-11 h-11 rounded-xl flex items-center justify-center shrink-0 border border-transparent transition-all group-hover/item:scale-110 group-hover/item:-rotate-2"
                          style={isSelected ? { backgroundColor: `${country.color}20`, borderColor: `${country.color}40` } : { backgroundColor: 'transparent' }}
                        >
                          <span className="text-3xl leading-none filter drop-shadow-sm" aria-hidden="true">{country.flag}</span>
                        </div>
                        <div className="flex flex-col items-start overflow-hidden">
                          <span className={`text-base tracking-tight transition-colors ${isSelected ? 'text-slate-900 dark:text-white' : 'text-slate-700 dark:text-slate-300'}`} style={isSelected ? { color: country.color } : {}}>
                            {country.nameAr}
                          </span>
                          <span className="text-[9px] text-slate-400 dark:text-slate-500 uppercase tracking-[0.2em] font-black">{country.nameEn}</span>
                        </div>
                      </span>
                      {isSelected && (
                        <div 
                          className="p-2 rounded-xl shadow-lg animate-in zoom-in-75 slide-in-from-right-2 duration-300"
                          style={{ backgroundColor: country.color, color: 'white' }}
                        >
                          <Check className="w-4 h-4" aria-hidden="true" />
                        </div>
                      )}
                    </button>
                  </li>
                );
              })
            )}
          </ul>
        </div>
      )}
    </div>
  );
};

