const App: React.FC = () => {
  const [origin, setOrigin] = useState<Country | null>(null);
  const [destination, setDestination] = useState<Country | null>(null);
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<VisaInfoResponse | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [viewMode, setViewMode] = useState<'form' | 'map'>('form');
  const [showCopyToast, setShowCopyToast] = useState(false);
  const searchFormRef = useRef<HTMLDivElement>(null);
  const [theme, setTheme] = useState<'light' | 'dark'>('light');

  // Handle Initial State from URL
  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const fromCode = params.get('from');
    const toCode = params.get('to');

    let foundOrigin = null;
    let foundDest = null;

    if (fromCode) {
      foundOrigin = COUNTRIES.find(c => c.code === fromCode.toUpperCase()) || null;
      if (foundOrigin) setOrigin(foundOrigin);
    }
    if (toCode) {
      foundDest = COUNTRIES.find(c => c.code === toCode.toUpperCase()) || null;
      if (foundDest) setDestination(foundDest);
    }

    if (foundOrigin && foundDest && foundOrigin.code !== foundDest.code) {
      handleSearchInternal(foundOrigin, foundDest);
    }
  }, []);

  // Safe URL State Persistence
  useEffect(() => {
    const params = new URLSearchParams();
    if (origin) params.set('from', origin.code);
    if (destination) params.set('to', destination.code);

    const newSearch = params.toString() ? '?' + params.toString() : '';
    // Use relative path for replaceState to avoid ERR_FILE_NOT_FOUND in some sandboxes
    try {
      window.history.replaceState({}, '', window.location.pathname + newSearch);
    } catch (e) {
      console.warn("History state update failed", e);
    }
  }, [origin, destination]);

  useEffect(() => {
    const savedTheme = localStorage.getItem('theme');
    if (savedTheme === 'dark' || (!savedTheme && window.matchMedia('(prefers-color-scheme: dark)').matches)) {
      setTheme('dark');
    } else {
      setTheme('light');
    }
  }, []);

  useEffect(() => {
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [theme]);

  const toggleTheme = () => setTheme(prev => prev === 'light' ? 'dark' : 'light');

  const handleShare = async () => {
    // Construct absolute URL reliably
    const shareUrl = window.location.origin + window.location.pathname + window.location.search;

    const shareData = {
      title: 'دليل التأشيرات العالمي',
      text: result 
        ? `تعرف على متطلبات السفر من ${origin?.nameAr} إلى ${destination?.nameAr}`
        : 'أداة ذكية لاكتشاف متطلبات التأشيرة لأي دولة في العالم.',
      url: shareUrl,
    };

    if (navigator.share) {
      try {
        await navigator.share(shareData);
        return;
      } catch (err) {
        console.log('Share failed', err);
      }
    }

    // Comprehensive Copy Fallback
    try {
      if (navigator.clipboard && navigator.clipboard.writeText) {
        await navigator.clipboard.writeText(shareUrl);
      } else {
        const textArea = document.createElement("textarea");
        textArea.value = shareUrl;
        textArea.style.position = "fixed";
        textArea.style.left = "-9999px";
        document.body.appendChild(textArea);
        textArea.select();
        document.execCommand('copy');
        document.body.removeChild(textArea);
      }
      setShowCopyToast(true);
      setTimeout(() => setShowCopyToast(false), 3000);
    } catch (err) {
      alert('يرجى نسخ هذا الرابط: ' + shareUrl);
    }
  };

  const handleSwap = () => {
    setOrigin(destination);
    setDestination(origin);
  };

  const handleSearchInternal = async (o: Country, d: Country) => {
    setLoading(true);
    setError(null);
    setResult(null);
    try {
      const data = await getVisaRequirements({ origin: o, destination: d });
      setResult(data);
    } catch (err: any) {
      setError(err.message || "حدث خطأ غير متوقع");
    } finally {
      setLoading(false);
    }
  };

  const handleSearch = () => {
    if (!origin || !destination) return;
    handleSearchInternal(origin, destination);
  };

  const handleReset = () => {
    setResult(null);
    setOrigin(null);
    setDestination(null);
    setError(null);
    window.history.replaceState({}, '', window.location.pathname);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const getErrorUI = (msg: string) => {
    if (msg.includes('اتصال') || msg.includes('الإنترنت') || msg.includes('Failed to fetch')) {
      return { title: "انقطاع في الاتصال", icon: <CloudOff className="w-6 h-6 text-blue-500 shrink-0" />, className: "bg-blue-50 border-blue-100 text-blue-900 dark:bg-blue-900/20 dark:border-blue-800 dark:text-blue-200" };
    }
    return { title: "خطأ غير متوقع", icon: <AlertTriangle className="w-6 h-6 text-red-600 shrink-0" />, className: "bg-red-50 border-red-100 text-red-900 dark:bg-red-900/20 dark:border-red-800 dark:text-red-200" };
  };

  const isFormValid = origin && destination && origin.code !== destination.code;

  return (
    <div className="min-h-screen bg-gradient-to-b from-slate-50 to-slate-100 dark:from-slate-950 dark:to-slate-900 text-slate-900 dark:text-slate-50 pb-20 transition-colors duration-300">

      <header className="bg-white/80 dark:bg-slate-900/80 backdrop-blur-md border-b border-slate-200 dark:border-slate-800 sticky top-0 z-40 transition-colors duration-300">
        <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3 cursor-pointer" onClick={handleReset}>
            <div className="w-10 h-10 bg-gradient-to-tr from-emerald-600 to-teal-500 rounded-lg flex items-center justify-center text-white shadow-lg shadow-emerald-200 dark:shadow-emerald-900/20">
               <Globe2 className="w-6 h-6" />
            </div>
            <h1 className="text-xl font-bold text-slate-800 dark:text-white hidden sm:block">دليل التأشيرات</h1>
          </div>
          <div className="flex items-center gap-2">
             <button 
               type="button"
               onClick={handleShare}
               className="p-2.5 rounded-xl text-slate-500 hover:bg-slate-100 dark:text-slate-400 dark:hover:bg-slate-800 transition-all flex items-center gap-2 active:scale-95 group/share"
               title="مشاركة"
             >
               <Share2 className="w-5 h-5 group-hover/share:text-emerald-500 transition-colors" />
               <span className="text-xs font-bold hidden md:block">مشاركة</span>
             </button>
             <button 
               type="button"
               onClick={toggleTheme}
               className="p-2.5 rounded-xl text-slate-500 hover:bg-slate-100 dark:text-slate-400 dark:hover:bg-slate-800 transition-colors active:scale-95"
               title={theme === 'light' ? 'داكن' : 'فاتح'}
             >
               {theme === 'light' ? <Moon className="w-5 h-5" /> : <Sun className="w-5 h-5" />}
             </button>
          </div>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 py-10">
        <div className="text-center mb-12">
          <h2 className="text-3xl md:text-4xl font-extrabold text-slate-900 dark:text-white mb-2 leading-tight">
            اكتشف متطلبات السفر <br className="hidden md:block" />
            <span className="text-transparent bg-clip-text bg-gradient-to-r from-emerald-600 to-teal-500 dark:from-emerald-400 dark:to-teal-300">إلى أي مكان في العالم</span>
          </h2>
          <h3 className="text-xl font-bold text-emerald-700/70 dark:text-emerald-400/70 mb-6 tracking-wider font-sans">Global Eis</h3>
        </div>

        <div className="flex justify-center mb-8">
            <div className="inline-flex p-1.5 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-2xl shadow-sm">
                <button type="button" onClick={() => setViewMode('form')} className={`flex items-center gap-2 px-6 py-2.5 rounded-xl font-bold text-sm transition-all ${viewMode === 'form' ? 'bg-emerald-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50 dark:hover:bg-slate-800'}`}>
                    <ListIcon className="w-4 h-4" /> القائمة
                </button>
                <button type="button" onClick={() => setViewMode('map')} className={`flex items-center gap-2 px-6 py-2.5 rounded-xl font-bold text-sm transition-all ${viewMode === 'map' ? 'bg-emerald-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50 dark:hover:bg-slate-800'}`}>
                    <MapIcon className="w-4 h-4" /> الخريطة
                </button>
            </div>
        </div>

        {viewMode === 'map' && (
            <div className="mb-10 animate-in fade-in zoom-in-95 duration-500">
                <InteractiveMap origin={origin} destination={destination} onSelectOrigin={setOrigin} onSelectDestination={setDestination} theme={theme} />
            </div>
        )}

        <div ref={searchFormRef} className="bg-white dark:bg-slate-900 rounded-2xl shadow-xl shadow-slate-200/50 dark:shadow-slate-950/50 border border-white dark:border-slate-800 ring-1 ring-slate-100 dark:ring-slate-800 p-6 md:p-8 mb-10 relative overflow-hidden transition-colors duration-300">
          <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-emerald-500 via-teal-400 to-cyan-500" />
          <div className="grid grid-cols-1 md:grid-cols-7 gap-6 items-end">
            <div className="md:col-span-3"><CountryCombobox label="أحمل جواز سفر من" countries={COUNTRIES} selectedCountry={origin} onSelect={setOrigin} placeholder="اختر دولتك" /></div>
            <div className="md:col-span-1 flex justify-center pb-2"><button type="button" onClick={handleSwap} className="w-10 h-10 rounded-full bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 flex items-center justify-center text-slate-400 dark:text-slate-500 hover:bg-slate-100 dark:hover:bg-slate-700 hover:text-emerald-600 dark:hover:text-emerald-400 rotate-90 md:rotate-0 transition-all duration-200 focus:outline-none focus:ring-2 focus:ring-emerald-500/50"><ArrowLeft className="w-5 h-5" /></button></div>
            <div className="md:col-span-3"><CountryCombobox label="أريد السفر إلى" countries={COUNTRIES} selectedCountry={destination} onSelect={setDestination} placeholder="اختر الوجهة" /></div>
          </div>
          <div className="mt-8 flex flex-col sm:flex-row items-center justify-center gap-4">
            <button type="button" onClick={handleSearch} disabled={!isFormValid || loading} className={`group relative flex items-center justify-center gap-2 px-8 py-4 rounded-xl font-bold text-lg w-full sm:w-auto md:min-w-[240px] transition-all duration-300 shadow-lg shadow-emerald-200 dark:shadow-emerald-900/20 ${!isFormValid ? 'bg-slate-100 dark:bg-slate-800 text-slate-400 dark:text-slate-500 cursor-not-allowed' : 'bg-emerald-600 hover:bg-emerald-700 text-white hover:shadow-emerald-300 dark:hover:shadow-emerald-900/40 hover:-translate-y-0.5 active:translate-y-0'}`}>
              {loading ? <><Spinner className="h-5 w-5 text-white" /><span>جاري البحث...</span></> : <><Sparkles className="w-5 h-5" /><span>فحص المتطلبات</span></>}
            </button>
            {result && <button type="button" onClick={handleReset} disabled={loading} className="flex items-center justify-center gap-2 px-6 py-4 rounded-xl font-bold text-lg w-full sm:w-auto bg-white dark:bg-slate-800 text-slate-700 dark:text-slate-300 border border-slate-200 dark:border-slate-700 hover:bg-slate-50 dark:hover:bg-slate-700 hover:border-slate-300 dark:hover:border-slate-600 transition-all duration-200"><RotateCcw className="w-5 h-5" /><span>بحث جديد</span></button>}
          </div>
        </div>

        {error && (() => {
          const errorUI = getErrorUI(error);
          return (
            <div className={`${errorUI.className} border rounded-xl p-4 mb-8 flex items-start gap-3 shadow-sm animate-in fade-in slide-in-from-top-2`}>
              <div className="mt-0.5">{errorUI.icon}</div>
              <div className="flex-1"><h3 className="font-bold mb-1">{errorUI.title}</h3><p className="text-sm leading-relaxed opacity-90">{error}</p></div>
              <button type="button" onClick={() => setError(null)} className="opacity-50 hover:opacity-100 p-1 rounded-full transition-opacity"><X className="w-5 h-5" /></button>
            </div>
          );
        })()}

        {result && origin && destination && <VisaResult data={result} origin={origin} destination={destination} onRefresh={handleSearch} />}

        {!result && !loading && (
          <div className="mb-12 animate-in fade-in slide-in-from-bottom-4 duration-700 delay-100">
             <div className="flex items-center gap-2 mb-4 px-1"><TrendingUp className="w-5 h-5 text-emerald-600 dark:text-emerald-400" /><h3 className="text-lg font-bold text-slate-800 dark:text-white">وجهات سفر شائعة</h3></div>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
              {FEATURED_DESTINATIONS.map((dest) => <FeaturedDestinationCard key={dest.code} dest={dest} onClick={() => { const country = COUNTRIES.find(c => c.code === dest.code); if (country) { setDestination(country); searchFormRef.current?.scrollIntoView({ behavior: 'smooth', block: 'center' }); } }} />)}
            </div>
          </div>
        )}
      </main>

      {/* Toast Notification for Link Copy */}
      <div className={`fixed bottom-8 left-1/2 -translate-x-1/2 z-[100] transition-all duration-500 transform ${showCopyToast ? 'translate-y-0 opacity-100' : 'translate-y-20 opacity-0 pointer-events-none'}`}>
          <div className="bg-slate-900 dark:bg-emerald-600 text-white px-6 py-3 rounded-2xl shadow-2xl flex items-center gap-3 border border-white/10">
              <CheckCircle2 className="w-5 h-5 text-emerald-400 dark:text-white" />
              <span className="font-bold text-sm">تم نسخ الرابط بنجاح!</span>
          </div>
      </div>

      <footer className="text-center py-8 text-slate-400 dark:text-slate-500 text-sm border-t border-slate-200 dark:border-slate-800 mt-auto bg-slate-50 dark:bg-slate-950 font-sans transition-colors duration-300" dir="ltr">
        <p className="flex flex-col sm:flex-row items-center justify-center gap-1">
          <span>Developed By</span>
          <span className="font-extrabold text-emerald-600 dark:text-emerald-400 text-lg tracking-wide">Ahmed Tork</span>
        </p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { ArrowLeft, Sparkles, Map, Clock, DollarSign, AlertTriangle, X, CloudOff, ShieldAlert, ServerCrash, Moon, Sun, Lock, RotateCcw, Globe2, TrendingUp, Map as MapIcon, List as ListIcon, Share2, CheckCircle2 } from 'lucide-react';
import { COUNTRIES } from './constants';
import { Country, VisaInfoResponse } from './types';
import { getVisaRequirements } from './services/geminiService';
import CountryCombobox from './components/CountryCombobox';
import VisaResult from './components/VisaResult';
import InteractiveMap from './components/InteractiveMap';

// Reusable Spinner Component
