  },
  {
    code: 'TR',
    name: 'تركيا',
    flag: '🇹🇷',
    image: 'https://images.unsplash.com/photo-1524231757912-21f4fe3a7200?auto=format&fit=crop&w=600&q=80',
    summary: 'تأشيرة إلكترونية (E-Visa) أو ملصق حسب الفئة العمرية.',
