  const searchFormRef = useRef<HTMLDivElement>(null);
  const [theme, setTheme] = useState<'light' | 'dark'>('light');

  // Load initial state from URL safely
  useEffect(() => {
    try {
      const url = new URL(window.location.href);
      const fromCode = url.searchParams.get('from');
      const toCode = url.searchParams.get('to');

      let foundOrigin = null;
      let foundDest = null;

      if (fromCode) {
        foundOrigin = COUNTRIES.find(c => c.code === fromCode.toUpperCase()) || null;
        if (foundOrigin) setOrigin(foundOrigin);
      }
      if (toCode) {
        foundDest = COUNTRIES.find(c => c.code === toCode.toUpperCase()) || null;
        if (foundDest) setDestination(foundDest);
      }

      if (foundOrigin && foundDest && foundOrigin.code !== foundDest.code) {
        handleSearchInternal(foundOrigin, foundDest);
      }
    } catch (e) {
      console.warn("Initial URL parse skipped or failed");
    }
  }, []);

  // Sync state to URL without reloading, avoiding origin mangling
  useEffect(() => {
    try {
      const url = new URL(window.location.href);
      if (origin) url.searchParams.set('from', origin.code);
      else url.searchParams.delete('from');

      if (destination) url.searchParams.set('to', destination.code);
      else url.searchParams.delete('to');

      // Stay within the same document context
      window.history.replaceState({}, '', url.pathname + url.search);
    } catch (e) {
      console.warn("History state update skipped");
    }
  }, [origin, destination]);

  useEffect(() => {
    const savedTheme = localStorage.getItem('theme');
    if (savedTheme === 'dark' || (!savedTheme && window.matchMedia('(prefers-color-scheme: dark)').matches)) {
      setTheme('dark');
    } else {
      setTheme('light');
    }
  }, []);

  useEffect(() => {
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [theme]);

