    let shareUrl = window.location.href;
    try {
      const url = new URL(window.location.href);
      if (origin) url.searchParams.set('from', origin.code);
      if (destination) url.searchParams.set('to', destination.code);
      shareUrl = url.toString();
    } catch (e) {
      // Fallback to simpler URL construction if URL API fails
      shareUrl = window.location.origin + window.location.pathname + (origin ? `?from=${origin.code}` : '') + (destination ? `&to=${destination.code}` : '');
    }

    const shareData = {
      title: 'دليل التأشيرات العالمي',
