/**
 * Fetch visa requirements from Gemini with Google Search grounding.
 */
export const getVisaRequirements = async (params: VisaRequestParams): Promise<VisaInfoResponse> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const destCode = params.destination.code;
    const specialInstructions = VISA_RULES[destCode] || "";

    const prompt = `
      **ROLE**: SENIOR GLOBAL VISA COMPLIANCE OFFICER.
      **CONTEXT**: Current Date is 2026.
      **TASK**: Generate a professional visa requirement report based on MANDATORY 2026 regulations.

      **APPLICANT**: ${params.origin.nameEn} (${params.origin.nameAr})
      **DESTINATION**: ${params.destination.nameEn} (${params.destination.nameAr})

      ${specialInstructions}
      ${['FR', 'DE', 'IT', 'ES', 'AT', 'BE', 'NL'].includes(destCode) ? ETIAS_RULE : ''}

      **STRICT INSTRUCTIONS**:
      1. Use Google Search to find the LATEST 2026 fees and digital application links.
      2. If destination is United Kingdom (GB), reflect the FULL digital eVisa status.
      3. If destination is Europe, mention ETIAS if applicable for the origin.
      4. If destination is Thailand, check for the new ETA system status.
      5. List exact fees in original currency and equivalent in ${params.origin.currencyCode}.
      6. Format in professional Arabic Markdown with icons.

      **OUTPUT STRUCTURE**:
      # 🏛️ تقرير متطلبات التأشيرة (تحديث 2026)
      ## 1. الحالة والنوع (Visa Status)
      ## 2. 💰 الرسوم والتكاليف (2026 Fees)
      ## 3. 📂 المستندات الرقمية والورقية
      ## 4. ⏳ المواعيد والمدة المتوقعة
      ## 5. 🚨 تحذيرات أمنية وقواعد الرفض
      ## 6. 🔗 روابط المنصات الرقمية الرسمية
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
      },
    });

    const markdown = response.text || "لم يتم العثور على بيانات محدثة لعام 2026.";
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    const sources = groundingChunks
      ?.filter((chunk: any) => chunk.web?.uri && chunk.web?.title)
      .map((chunk: any) => ({
        title: chunk.web!.title,
        url: chunk.web!.uri
      })) || [];

    return {
      markdown,
      sources: Array.from(new Map(sources.map((s: any) => [s.url, s])).values()) as any,
      generatedAt: new Date().toISOString()
    };

  } catch (error: any) {
    console.error("Gemini API Error:", error);
    throw new Error(error.message || "فشل في جلب البيانات المحدثة من أنظمة السفارة.");
  }
};

/**
 * Analyze a bank statement file (image/pdf) using Gemini Vision capabilities.
 */
export const analyzeBankStatement = async (file: File): Promise<BankAnalysisResult> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    // Convert file to base64 for Gemini inlineData
    const base64Data = await new Promise<string>((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = () => {
        const base64 = (reader.result as string).split(',')[1];
        resolve(base64);
      };
      reader.onerror = reject;
      reader.readAsDataURL(file);
    });

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        {
          parts: [
            {
              inlineData: {
                data: base64Data,
                mimeType: file.type || 'image/jpeg',
              },
            },
            {
              text: `Analyze this bank statement for a UK or Schengen visa application. 
              Check for:
              1. Funds Parking (unexplained large deposits).
              2. Sufficient balance (assume a budget of $150/day for 15 days).
              3. Regular salary or income stream.
              4. Any suspicious activity that might cause rejection.
              Return the analysis in professional Arabic in JSON format.`,
            },
          ],
        },
      ],
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summaryAr: { type: Type.STRING, description: 'Summary of the financial status in Arabic.' },
            riskLevel: { type: Type.STRING, description: 'Risk assessment: Low, Medium, or High.' },
            findings: { type: Type.ARRAY, items: { type: Type.STRING }, description: 'List of specific observations.' },
            recommendations: { type: Type.ARRAY, items: { type: Type.STRING }, description: 'Steps to improve the application.' }
          },
          required: ["summaryAr", "riskLevel", "findings", "recommendations"],
        },
      },
    });

    if (!response.text) {
      throw new Error("No analysis generated");
    }

    return JSON.parse(response.text.trim());
  } catch (error: any) {
    console.error("Bank analysis error:", error);
    throw new Error("فشل في تحليل كشف الحساب. يرجى التأكد من وضوح الملف.");
  }
};

