    try {
      const currentParams = new URLSearchParams(window.location.search);
      const fromParam = currentParams.get('from');
      const toParam = currentParams.get('to');

      const newFrom = origin?.code || '';
      const newTo = destination?.code || '';

      if (fromParam !== newFrom || toParam !== newTo) {
        const nextParams = new URLSearchParams();
        if (origin) nextParams.set('from', origin.code);
        if (destination) nextParams.set('to', destination.code);

        const queryString = nextParams.toString();
        const newUrl = window.location.pathname + (queryString ? '?' + queryString : '');

        window.history.replaceState({}, '', newUrl);
      }
    } catch (e) {}
