};

const CurrencyConverter: React.FC<{ origin: Country; destination: Country }> = ({ origin, destination }) => {
  const [amount, setAmount] = useState<number | string>(100);
  const [fromCurrency, setFromCurrency] = useState(destination.currencyCode || 'USD');
  const [toCurrency, setToCurrency] = useState('USD');
  const [result, setResult] = useState<number | null>(null);

  const currencyOptions = useMemo(() => {
    return Array.from(new Set(['USD', 'EUR', origin.currencyCode, destination.currencyCode].filter(Boolean))) as string[];
  }, [origin, destination]);

  const handleConvert = () => {
    const val = parseFloat(amount.toString());
    if (isNaN(val)) {
      setResult(null);
      return;
    }
    const fromRate = EXCHANGE_RATES[fromCurrency] || 1;
    const toRate = EXCHANGE_RATES[toCurrency] || 1;
    setResult((val / fromRate) * toRate);
  };

  useEffect(() => {
    handleConvert();
  }, [amount, fromCurrency, toCurrency]);

  const swapCurrencies = () => {
    const temp = fromCurrency;
    setFromCurrency(toCurrency);
    setToCurrency(temp);
  };

  return (
    <div className="mt-8 bg-white dark:bg-slate-950 rounded-2xl border border-slate-200 dark:border-slate-800 overflow-hidden shadow-sm">
      <div className="bg-slate-50 dark:bg-slate-900 px-5 py-4 border-b border-slate-100 dark:border-slate-800 flex flex-col sm:flex-row items-start sm:items-center justify-between gap-3">
        <div className="flex items-center gap-2">
            <IconManager type="currency" className="w-5 h-5 text-emerald-600 dark:text-emerald-400" />
