import { GoogleGenAI, Type } from "@google/genai";
import { VisaRequestParams, VisaInfoResponse, BankAnalysisResult } from "../types";

export type { BankAnalysisResult };

/**
 * Fetch visa requirements from Gemini with Google Search grounding.
 */
export const getVisaRequirements = async (params: VisaRequestParams): Promise<VisaInfoResponse> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const prompt = `
      **ROLE**: SENIOR GLOBAL VISA COMPLIANCE OFFICER.
      **TASK**: Generate a professional visa requirement report.

      **APPLICANT**: ${params.origin.nameEn} (${params.origin.nameAr})
      **DESTINATION**: ${params.destination.nameEn} (${params.destination.nameAr})

      **STRICT INSTRUCTIONS**:
      1. Use Google Search to find the LATEST fees and application links.
      2. List exact fees in original currency and equivalent in ${params.origin.currencyCode}.
      3. Format in professional Arabic Markdown with icons.

      **OUTPUT STRUCTURE**:
      # 🏛️ تقرير متطلبات التأشيرة
      ## 1. الحالة والنوع (Visa Status)
      ## 2. 💰 الرسوم والتكاليف
      ## 3. 📂 المستندات المطلوبة
      ## 4. ⏳ المواعيد والمدة المتوقعة
      ## 5. 🚨 ملاحظات وتحذيرات هامة
      ## 6. 🔗 الروابط الرسمية للتقديم
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
      },
    });

    const markdown = response.text || "لم يتم العثور على بيانات.";
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    const sources = groundingChunks
      ?.filter((chunk: any) => chunk.web?.uri && chunk.web?.title)
      .map((chunk: any) => ({
        title: chunk.web!.title,
        url: chunk.web!.uri
      })) || [];

    return {
      markdown,
      sources: Array.from(new Map(sources.map((s: any) => [s.url, s])).values()) as any,
      generatedAt: new Date().toISOString()
    };

  } catch (error: any) {
    console.error("Gemini API Error:", error);
    throw new Error(error.message || "فشل في جلب البيانات من أنظمة السفارة.");
  }
};

/**
 * Analyze a bank statement file (image/pdf) using Gemini Vision capabilities.
 */
export const analyzeBankStatement = async (file: File): Promise<BankAnalysisResult> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const base64Data = await new Promise<string>((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = () => {
        const base64 = (reader.result as string).split(',')[1];
        resolve(base64);
      };
      reader.onerror = reject;
      reader.readAsDataURL(file);
    });

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        {
          parts: [
            {
              inlineData: {
                data: base64Data,
                mimeType: file.type || 'image/jpeg',
              },
            },
            {
              text: `Analyze this bank statement for a visa application. Return the analysis in professional Arabic in JSON format.`,
            },
          ],
        },
      ],
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summaryAr: { type: Type.STRING },
            riskLevel: { type: Type.STRING },
            findings: { type: Type.ARRAY, items: { type: Type.STRING } },
            recommendations: { type: Type.ARRAY, items: { type: Type.STRING } }
          },
          required: ["summaryAr", "riskLevel", "findings", "recommendations"],
        },
      },
    });

    if (!response.text) throw new Error("No analysis generated");
    return JSON.parse(response.text.trim());
  } catch (error: any) {
    throw new Error("فشل في تحليل كشف الحساب.");
  }
};

import React, { useState, useEffect, useRef, useId, useMemo } from 'react';
import { Country } from '../types';
import { ChevronDown, Search, Check, X } from 'lucide-react';

interface CountryComboboxProps {
  label: string;
  countries: Country[];
  selectedCountry: Country | null;
  onSelect: (country: Country) => void;
  placeholder?: string;
}

const normalizeText = (text: string): string => {
  return text.toLowerCase().replace(/[أإآ]/g, 'ا').replace(/ة/g, 'ه').replace(/ى/g, 'ي').trim();
};

const CountryCombobox: React.FC<CountryComboboxProps> = ({
  label,
  countries,
  selectedCountry,
  onSelect,
  placeholder = "اختر دولة..."
}) => {
  const [isOpen, setIsOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const wrapperRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);
  const uniqueId = useId();

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (wrapperRef.current && !wrapperRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  useEffect(() => {
    if (isOpen && inputRef.current) inputRef.current.focus();
  }, [isOpen]);

  const filteredCountries = useMemo(() => {
    const query = normalizeText(searchQuery);
    if (!query) return countries;
    return countries.filter(c => 
      normalizeText(c.nameAr).includes(query) || 
      normalizeText(c.nameEn).includes(query)
    );
  }, [searchQuery, countries]);

  return (
    <div className="w-full relative" ref={wrapperRef}>
      <label className="block text-[10px] font-bold mb-1.5 text-slate-500 dark:text-slate-400 uppercase tracking-wider">{label}</label>
      <button
        type="button"
        onClick={() => setIsOpen(!isOpen)}
        className={`w-full flex items-center justify-between bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-xl px-4 py-3 text-right transition-all ${isOpen ? 'ring-2 ring-emerald-500 border-transparent shadow-lg' : 'hover:border-slate-300 dark:hover:border-slate-700 shadow-sm'}`}
      >
        <span className={`flex items-center gap-3 truncate ${!selectedCountry ? 'text-slate-400' : 'text-slate-900 dark:text-white'}`}>
          {selectedCountry ? (
            <><span className="text-xl">{selectedCountry.flag}</span><span className="font-bold">{selectedCountry.nameAr}</span></>
          ) : placeholder}
        </span>
        <ChevronDown className={`w-4 h-4 text-slate-400 transition-transform ${isOpen ? 'rotate-180' : ''}`} />
      </button>

      {isOpen && (
        <div className="absolute z-50 w-full mt-2 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-xl shadow-xl overflow-hidden animate-in fade-in slide-in-from-top-2 duration-200">
          <div className="p-3 border-b border-slate-100 dark:border-slate-800">
            <div className="relative">
              <Search className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
              <input
                ref={inputRef}
                type="text"
                className="w-full pr-10 pl-4 py-2 bg-slate-50 dark:bg-slate-800 rounded-lg text-sm outline-none focus:ring-1 focus:ring-emerald-500"
                placeholder="ابحث..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
            </div>
          </div>
          <ul className="max-h-60 overflow-y-auto">
            {filteredCountries.map((country) => (
              <li key={country.code}>
                <button
                  onClick={() => { onSelect(country); setIsOpen(false); setSearchQuery(''); }}
                  className="w-full flex items-center gap-3 px-4 py-2.5 text-right hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
                >
                  <span className="text-lg">{country.flag}</span>
                  <span className="text-sm font-medium">{country.nameAr}</span>
                </button>
              </li>
            ))}
          </ul>
        </div>
      )}
    </div>
  );
};

