import { GoogleGenAI, Type } from "@google/genai";
import { VisaRequestParams, VisaInfoResponse, BankAnalysisResult } from "../types";

export type { BankAnalysisResult };

/**
 * Fetch visa requirements from Gemini with Google Search grounding.
 */
export const getVisaRequirements = async (params: VisaRequestParams): Promise<VisaInfoResponse> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const prompt = `
      **ROLE**: SENIOR GLOBAL VISA COMPLIANCE OFFICER.
      **TASK**: Generate a professional visa requirement report.

      **APPLICANT**: ${params.origin.nameEn} (${params.origin.nameAr})
      **DESTINATION**: ${params.destination.nameEn} (${params.destination.nameAr})

      **STRICT INSTRUCTIONS**:
      1. Use Google Search to find the LATEST requirements, fees, and application links.
      2. If destination is United Kingdom (GB), reflect the current digital eVisa status.
      3. List exact fees in original currency and equivalent in ${params.origin.currencyCode}.
      4. Format in professional Arabic Markdown with icons.

      **OUTPUT STRUCTURE**:
      # 🏛️ تقرير متطلبات التأشيرة
      ## 1. الحالة والنوع (Visa Status)
      ## 2. 💰 الرسوم والتكاليف
      ## 3. 📂 المستندات المطلوبة
      ## 4. ⏳ المواعيد والمدة المتوقعة
      ## 5. 🚨 تحذيرات أمنية وقواعد الرفض
      ## 6. 🔗 روابط المنصات الرقمية الرسمية
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
      },
    });

    const markdown = response.text || "لم يتم العثور على بيانات محدثة.";
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    const sources = groundingChunks
      ?.filter((chunk: any) => chunk.web?.uri && chunk.web?.title)
      .map((chunk: any) => ({
        title: chunk.web!.title,
        url: chunk.web!.uri
      })) || [];

    return {
      markdown,
      sources: Array.from(new Map(sources.map((s: any) => [s.url, s])).values()) as any,
      generatedAt: new Date().toISOString()
    };

  } catch (error: any) {
    console.error("Gemini API Error:", error);
    throw new Error(error.message || "فشل في جلب البيانات من أنظمة السفارة.");
  }
};

/**
 * Analyze a bank statement file (image/pdf) using Gemini Vision capabilities.
 */
export const analyzeBankStatement = async (file: File): Promise<BankAnalysisResult> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const base64Data = await new Promise<string>((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = () => {
        const base64 = (reader.result as string).split(',')[1];
        resolve(base64);
      };
      reader.onerror = reject;
      reader.readAsDataURL(file);
    });

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        {
          parts: [
            {
              inlineData: {
                data: base64Data,
                mimeType: file.type || 'image/jpeg',
              },
            },
            {
              text: `Analyze this bank statement for a visa application. 
              Return the analysis in professional Arabic in JSON format.`,
            },
          ],
        },
      ],
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summaryAr: { type: Type.STRING },
            riskLevel: { type: Type.STRING },
            findings: { type: Type.ARRAY, items: { type: Type.STRING } },
            recommendations: { type: Type.ARRAY, items: { type: Type.STRING } }
          },
          required: ["summaryAr", "riskLevel", "findings", "recommendations"],
        },
      },
    });

    if (!response.text) throw new Error("No analysis generated");
    return JSON.parse(response.text.trim());
  } catch (error: any) {
    throw new Error("فشل في تحليل كشف الحساب.");
  }
};

import React, { useState, useEffect, useRef, useId, useMemo } from 'react';
import { Country } from '../types';
import { ChevronDown, Search, Check, X } from 'lucide-react';

interface CountryComboboxProps {
  label: string;
  countries: Country[];
  selectedCountry: Country | null;
  onSelect: (country: Country) => void;
  placeholder?: string;
}

/**
 * Normalizes text for robust searching:
 * - Removes specific Arabic diacritics
 * - Standardizes variations of Alef, Teh Marbuta, etc.
 * - Converts to lowercase
 */
const normalizeText = (text: string): string => {
  return text
    .toLowerCase()
    .replace(/[أإآ]/g, 'ا')
    .replace(/ة/g, 'ه')
    .replace(/ى/g, 'ي')
    .replace(/ؤ/g, 'و')
    .replace(/ئ/g, 'ي')
    .replace(/[^\w\s\u0600-\u06FF]/g, '') // Keep words and Arabic characters
    .trim();
};

/**
 * Computes Levenshtein distance for fuzzy matching
 */
const levenshteinDistance = (a: string, b: string): number => {
  if (a.length === 0) return b.length;
  if (b.length === 0) return a.length;

  const matrix = Array(b.length + 1).fill(null).map(() => Array(a.length + 1).fill(null));

  for (let i = 0; i <= b.length; i++) matrix[i][0] = i;
  for (let j = 0; j <= a.length; j++) matrix[0][j] = j;

  for (let i = 1; i <= b.length; i++) {
    for (let j = 1; j <= a.length; j++) {
      const cost = a[j - 1] === b[i - 1] ? 0 : 1;
      matrix[i][j] = Math.min(
        matrix[i - 1][j] + 1, // deletion
        matrix[i][j - 1] + 1, // insertion
        matrix[i - 1][j - 1] + cost // substitution
      );
    }
  }

  return matrix[b.length][a.length];
};

const CountryCombobox: React.FC<CountryComboboxProps> = ({
  label,
  countries,
  selectedCountry,
  onSelect,
  placeholder = "اختر دولة..."
}) => {
  const [isOpen, setIsOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [debouncedQuery, setDebouncedQuery] = useState('');
  const wrapperRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  const uniqueId = useId();
  const labelId = `label-${uniqueId}`;
  const listboxId = `listbox-${uniqueId}`;

  // Close when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (wrapperRef.current && !wrapperRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  // Focus input when opened
  useEffect(() => {
    if (isOpen && inputRef.current) {
      setTimeout(() => inputRef.current?.focus(), 50);
    }
  }, [isOpen]);

  // Debounce search query for performance
  useEffect(() => {
    const timer = setTimeout(() => setDebouncedQuery(searchQuery), 200);
    return () => clearTimeout(timer);
  }, [searchQuery]);

  // Pre-normalize country names
  const searchableCountries = useMemo(() => {
    return countries.map(country => ({
      ...country,
      normAr: normalizeText(country.nameAr),
      normEn: normalizeText(country.nameEn)
    }));
  }, [countries]);

  // Fuzzy Search Algorithm
  const filteredCountries = useMemo(() => {
    const query = normalizeText(debouncedQuery);
    if (!query) return countries;

    return searchableCountries
      .map(item => {
        const { normAr, normEn, ...country } = item;
        let score = 999;
        let match = false;

        // 1. Exact Match
        if (normAr === query || normEn === query) {
          score = 0;
          match = true;
        } 
        // 2. Starts With
        else if (normAr.startsWith(query) || normEn.startsWith(query)) {
          score = 10;
          match = true;
        } 
        // 3. Includes
        else if (normAr.includes(query) || normEn.includes(query)) {
          score = 20;
          match = true;
        } 
        // 4. Fuzzy Levenshtein (only for queries >= 3 chars)
        else if (query.length >= 3) {
          const distAr = levenshteinDistance(query, normAr);
          const distEn = levenshteinDistance(query, normEn);
          const threshold = Math.floor(query.length * 0.4) + 1; // Allow ~40% errors

          if (distAr <= threshold || distEn <= threshold) {
            score = 30 + Math.min(distAr, distEn);
            match = true;
          }
        }

        return { country, score, match };
      })
      .filter(item => item.match)
      .sort((a, b) => a.score - b.score)
      .map(item => item.country);
  }, [debouncedQuery, searchableCountries, countries]);

  const handleSelect = (country: Country) => {
    onSelect(country);
    setIsOpen(false);
    setSearchQuery('');
    setDebouncedQuery('');
  };

  const dynamicStyles = useMemo(() => {
    if (!selectedCountry) return {};
    return {
      borderColor: selectedCountry.color,
      boxShadow: isOpen ? `0 0 0 2px ${selectedCountry.color}30` : 'none'
    };
  }, [selectedCountry, isOpen]);

  return (
    <div className="w-full relative group" ref={wrapperRef}>
      <label 
        id={labelId}
        className={`block text-[10px] font-black mb-1.5 uppercase tracking-widest ${selectedCountry ? 'text-slate-900 dark:text-slate-200' : 'text-slate-400 dark:text-slate-500'}`}
      >
        {label}
      </label>

      <button
        type="button"
        onClick={() => setIsOpen(!isOpen)}
        aria-haspopup="listbox"
        aria-expanded={isOpen}
        aria-controls={listboxId}
        style={dynamicStyles}
        className={`
          w-full flex items-center justify-between 
          bg-white dark:bg-slate-900 border rounded-2xl px-4 py-3 text-right min-h-[64px]
          transition-all duration-300 relative z-10 focus:outline-none
          ${!selectedCountry ? 'border-slate-200 dark:border-slate-800 hover:border-emerald-400' : 'border-2'}
        `}
      >
        <span className="flex items-center gap-3 truncate text-right w-full">
          {selectedCountry ? (
            <>
              <span className="text-2xl drop-shadow-sm">{selectedCountry.flag}</span>
              <div className="flex flex-col items-start overflow-hidden">
                <span className="font-bold text-slate-900 dark:text-white truncate">{selectedCountry.nameAr}</span>
                <span className="text-[9px] text-slate-400 uppercase font-black">{selectedCountry.nameEn}</span>
              </div>
            </>
          ) : (
            <span className="text-slate-400 font-medium">{placeholder}</span>
          )}
        </span>
        <ChevronDown className={`w-5 h-5 transition-transform duration-300 ${isOpen ? 'rotate-180' : 'text-slate-300'}`} />
      </button>

      {isOpen && (
        <div className="absolute z-50 w-full mt-2 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-2xl shadow-2xl overflow-hidden animate-in fade-in slide-in-from-top-2 duration-200">
          <div className="p-3 border-b border-slate-100 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-900/50">
            <div className="relative">
              <Search className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
              <input
                ref={inputRef}
                type="text"
                className="w-full pr-10 pl-4 py-2.5 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl text-sm outline-none focus:ring-2 focus:ring-emerald-500/20"
                placeholder="ابحث باسم الدولة..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
              {searchQuery && (
                <button 
                  onClick={() => setSearchQuery('')}
                  className="absolute left-3 top-1/2 -translate-y-1/2 p-1 text-slate-300 hover:text-slate-500"
                >
                  <X className="w-4 h-4" />
                </button>
              )}
            </div>
          </div>
          <ul id={listboxId} role="listbox" className="max-h-72 overflow-y-auto custom-scrollbar">
            {filteredCountries.length === 0 ? (
              <li className="px-6 py-10 text-center text-slate-400 text-sm italic">لا توجد نتائج مطابقة</li>
            ) : (
              filteredCountries.map((country) => (
                <li key={country.code}>
                  <button
                    onClick={() => handleSelect(country)}
                    className={`
                      w-full flex items-center justify-between px-4 py-3 text-right hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors
                      ${selectedCountry?.code === country.code ? 'bg-emerald-50/50 dark:bg-emerald-900/10' : ''}
                    `}
                  >
                    <span className="flex items-center gap-3">
                      <span className="text-xl">{country.flag}</span>
                      <div className="flex flex-col items-start">
                        <span className="text-sm font-bold text-slate-700 dark:text-slate-200">{country.nameAr}</span>
                        <span className="text-[10px] text-slate-400 uppercase">{country.nameEn}</span>
                      </div>
                    </span>
                    {selectedCountry?.code === country.code && <Check className="w-4 h-4 text-emerald-500" />}
                  </button>
                </li>
              ))
            )}
          </ul>
        </div>
      )}
    </div>
  );
};

