export const getVisaRequirements = async (params: VisaRequestParams): Promise<VisaInfoResponse> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const destCode = params.destination.code;
    const specialInstructions = VISA_RULES[destCode] || "";

    const prompt = `
      **ROLE**: SENIOR GLOBAL VISA COMPLIANCE OFFICER.
      **TASK**: Generate a professional and accurate visa requirement report.

      **APPLICANT**: ${params.origin.nameEn} (${params.origin.nameAr})
      **DESTINATION**: ${params.destination.nameEn} (${params.destination.nameAr})

      ${specialInstructions}
      ${['FR', 'DE', 'IT', 'ES', 'AT', 'BE', 'NL'].includes(destCode) ? ETIAS_RULE : ''}

      **STRICT INSTRUCTIONS**:
      1. Use Google Search to find the LATEST requirements, fees, and application links.
      2. Reflect current digital shifts like UK eVisa and European ETIAS/EES.
      3. List exact fees in original currency and equivalent in ${params.origin.currencyCode}.
      4. Format in professional Arabic Markdown with icons.

      **OUTPUT STRUCTURE**:
      # 🏛️ تقرير متطلبات التأشيرة
      ## 1. الحالة والنوع (Visa Status)
      ## 2. 💰 الرسوم والتكاليف (Current Fees)
      ## 3. 📂 المستندات المطلوبة (الرقمية والورقية)
      ## 4. ⏳ المواعيد والمدة المتوقعة
      ## 5. 🚨 تحذيرات أمنية وأسباب الرفض الشائعة
      ## 6. 🔗 روابط المنصات الرسمية للتقديم
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
      },
    });

    const markdown = response.text || "لم يتم العثور على بيانات محدثة.";
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    const sources = groundingChunks
      ?.filter((chunk: any) => chunk.web?.uri && chunk.web?.title)
      .map((chunk: any) => ({
        title: chunk.web!.title,
        url: chunk.web!.uri
      })) || [];

    return {
      markdown,
      sources: Array.from(new Map(sources.map((s: any) => [s.url, s])).values()) as any,
      generatedAt: new Date().toISOString()
    };

  } catch (error: any) {
    console.error("Gemini API Error:", error);
    throw new Error(error.message || "فشل في جلب البيانات من أنظمة السفارة.");
  }
};

/**
 * Analyze a bank statement file (image/pdf) using Gemini Vision capabilities.
 */
export const analyzeBankStatement = async (file: File): Promise<BankAnalysisResult> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const base64Data = await new Promise<string>((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = () => {
        const base64 = (reader.result as string).split(',')[1];
        resolve(base64);
      };
      reader.onerror = reject;
      reader.readAsDataURL(file);
    });

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        {
          parts: [
            {
              inlineData: {
                data: base64Data,
                mimeType: file.type || 'image/jpeg',
              },
            },
            {
              text: `Analyze this bank statement for a UK or Schengen visa application. 
              Check for Funds Parking, sufficient balance, and regular income.
              Return the analysis in professional Arabic in JSON format.`,
            },
          ],
        },
      ],
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summaryAr: { type: Type.STRING },
            riskLevel: { type: Type.STRING },
            findings: { type: Type.ARRAY, items: { type: Type.STRING } },
            recommendations: { type: Type.ARRAY, items: { type: Type.STRING } }
          },
          required: ["summaryAr", "riskLevel", "findings", "recommendations"],
        },
      },
    });

    if (!response.text) throw new Error("No analysis generated");
    return JSON.parse(response.text.trim());
  } catch (error: any) {
    throw new Error("فشل في تحليل كشف الحساب.");
  }
};

