const VisaResult: React.FC<VisaResultProps> = ({ data, origin, destination, onRefresh }) => {
  const isUK = destination.code === 'GB';

  /**
   * Automatically decorates the markdown by injecting flag emojis next to country names.
   */
  const decoratedMarkdown = useMemo(() => {
    let text = data.markdown;

    // Sort by name length descending to ensure longer names (like "South Sudan") are handled before shorter ones ("Sudan")
    const sortedCountries = [...COUNTRIES].sort((a, b) => b.nameAr.length - a.nameAr.length);

    sortedCountries.forEach(country => {
      const name = country.nameAr;
      const flag = country.flag;

      // Escape for regex
      const escapedName = name.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');

      // Use a regex that replaces the name with "Flag Name" only if the flag isn't already there.
      // We check for the presence of the flag followed by optional whitespace using a capture group.
      const regex = new RegExp(`(${flag}\\s*)?${escapedName}`, 'g');

      text = text.replace(regex, (match, p1) => {
        // If p1 exists, it means the flag was already there, so return as is.
        if (p1) return match;
        // Otherwise, prepend the flag.
        return `${flag} ${name}`;
      });
    });

    return text;
  }, [data.markdown]);

  return (
    <div className="w-full animate-in fade-in slide-in-from-bottom-4 duration-500 pb-10">

      <div className="bg-white dark:bg-slate-900 rounded-3xl shadow-xl shadow-slate-200/50 dark:shadow-slate-950/50 border border-slate-100 dark:border-slate-800 overflow-hidden mb-6">
