          <button 
            onClick={onRefresh}
            className="p-3 rounded-2xl bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-400 hover:text-emerald-600 transition-all shadow-sm active:scale-95"
            title="تحديث البيانات"
          >
            <IconManager type="refresh" className="w-5 h-5" />
          </button>
        </div>

        <div className="p-8">
          <div className="prose prose-slate dark:prose-invert max-w-none text-right" dir="rtl">
