/**
 * Fetch visa requirements from Gemini with Google Search grounding focused on 2026.
 */
export const getVisaRequirements = async (params: VisaRequestParams): Promise<VisaInfoResponse> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const destCode = params.destination.code;
    const specialInstructions = VISA_RULES[destCode] || "";

    const prompt = `
      **ROLE**: SENIOR GLOBAL VISA COMPLIANCE OFFICER (Specialized in 2026 Regulations).
      **TASK**: Generate a professional and accurate visa requirement report specifically for the year **2026**.

      **APPLICANT**: ${params.origin.nameEn} (${params.origin.nameAr})
      **DESTINATION**: ${params.destination.nameEn} (${params.destination.nameAr})
      **TARGET YEAR**: 2026 (Include upcoming changes like ETIAS, EES, UK ETA, and JESTA).

      ${specialInstructions}
      ${['FR', 'DE', 'IT', 'ES', 'AT', 'BE', 'NL', 'GR', 'CH'].includes(destCode) ? ETIAS_RULE : ''}

      **STRICT INSTRUCTIONS**:
      1. Use Google Search to find requirements effective in **2026**.
      2. If certain fees or rules for 2026 are already announced (e.g., ETIAS fees), include them.
      3. Clearly distinguish between "Current" and "Planned 2026" changes.
      4. List exact fees in original currency and equivalent in ${params.origin.currencyCode}.
      5. Format in professional Arabic Markdown with high-quality icons.

      **OUTPUT STRUCTURE**:
      # 🏛️ دليل متطلبات التأشيرة (تحديث 2026)
      ## 1. الحالة والنوع (Visa Status 2026)
      ## 2. 💰 الرسوم والتكاليف المقررة لعام 2026
      ## 3. 📂 المستندات المطلوبة (مع التركيز على التقديم الرقمي)
      ## 4. ⏳ المواعيد ومدة المعالجة المتوقعة
      ## 5. 🚨 تحديثات 2026 (مثل ETIAS/EES/Digital Visas)
      ## 6. 🔗 المنصات الرسمية للتقديم لعام 2026
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
      },
    });

    const markdown = response.text || "لم يتم العثور على بيانات محدثة لعام 2026.";
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    const sources = groundingChunks
      ?.filter((chunk: any) => chunk.web?.uri && chunk.web?.title)
      .map((chunk: any) => ({
        title: chunk.web!.title,
        url: chunk.web!.uri
      })) || [];

    return {
      markdown,
      sources: Array.from(new Map(sources.map((s: any) => [s.url, s])).values()) as any,
      generatedAt: new Date().toISOString()
    };

  } catch (error: any) {
    console.error("Gemini API Error:", error);
    throw new Error(error.message || "فشل في جلب البيانات المحدثة لعام 2026.");
  }
};

/**
 * Analyze a bank statement file (image/pdf) using Gemini Vision capabilities.
 */
export const analyzeBankStatement = async (file: File): Promise<BankAnalysisResult> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const base64Data = await new Promise<string>((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = () => {
        const base64 = (reader.result as string).split(',')[1];
        resolve(base64);
      };
      reader.onerror = reject;
      reader.readAsDataURL(file);
    });

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        {
          parts: [
            {
              inlineData: {
                data: base64Data,
                mimeType: file.type || 'image/jpeg',
              },
            },
            {
              text: `Analyze this bank statement for a 2026 visa application. 
              Check for Funds Parking, sufficient balance, and regular income.
              Return the analysis in professional Arabic in JSON format.`,
            },
          ],
        },
      ],
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summaryAr: { type: Type.STRING },
            riskLevel: { type: Type.STRING },
            findings: { type: Type.ARRAY, items: { type: Type.STRING } },
            recommendations: { type: Type.ARRAY, items: { type: Type.STRING } }
          },
          required: ["summaryAr", "riskLevel", "findings", "recommendations"],
        },
      },
    });

    if (!response.text) throw new Error("No analysis generated");
    return JSON.parse(response.text.trim());
  } catch (error: any) {
    throw new Error("فشل في تحليل كشف الحساب.");
  }
};

