const extractTextFromNode = (node: any): string => {
  if (!node) return '';
  if (typeof node === 'string') return node;
  if (Array.isArray(node)) return node.map(extractTextFromNode).join('');
  if (typeof node === 'object' && node.props && node.props.children) {
    return extractTextFromNode(node.props.children);
  }
  return '';
};

const getSectionConfig = (text: string) => {
  const normText = text.toLowerCase();
  if (normText.includes('رسوم') || normText.includes('fees')) 
    return { type: 'fees', color: 'text-emerald-700 dark:text-emerald-400', border: 'border-emerald-500', bg: 'bg-emerald-50 dark:bg-emerald-900/10' };
  if (normText.includes('مستندات') || normText.includes('documents')) 
    return { type: 'docs', color: 'text-blue-700 dark:text-blue-400', border: 'border-blue-500', bg: 'bg-blue-50 dark:bg-blue-900/10' };
  if (normText.includes('رفض') || normText.includes('red flags') || normText.includes('warnings')) 
    return { type: 'alert', color: 'text-red-700 dark:text-red-400', border: 'border-red-500', bg: 'bg-red-50 dark:bg-red-900/10' };
  if (normText.includes('مواعيد') || normText.includes('timeline') || normText.includes('مدة')) 
    return { type: 'timeline', color: 'text-amber-700 dark:text-amber-400', border: 'border-amber-500', bg: 'bg-amber-50 dark:bg-amber-900/10' };
  if (normText.includes('حالة') || normText.includes('status')) 
    return { type: 'status', color: 'text-indigo-700 dark:text-indigo-400', border: 'border-indigo-500', bg: 'bg-indigo-50 dark:bg-indigo-900/10' };
  return null;
};

