  const [error, setError] = useState<string | null>(null);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsAnalyzing(true);
    setError(null);
    setResult(null);

    try {
      const analysis = await analyzeBankStatement(file);
      setResult(analysis);
    } catch (err: any) {
      setError(err.message || "فشل في تحليل كشف الحساب.");
