      reader.onload = () => resolve((reader.result as string).split(',')[1]);
      reader.onerror = reject;
      reader.readAsDataURL(file);
    });

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [{
        parts: [
          { inlineData: { data: base64Data, mimeType: file.type || 'image/jpeg' } },
          { text: "Analyze this bank statement for a 2026 visa. Check for Funds Parking and regular income. Result in Arabic JSON." }
        ]
      }],
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summaryAr: { type: Type.STRING },
            riskLevel: { type: Type.STRING },
            findings: { type: Type.ARRAY, items: { type: Type.STRING } },
            recommendations: { type: Type.ARRAY, items: { type: Type.STRING } }
          },
          required: ["summaryAr", "riskLevel", "findings", "recommendations"],
        },
      },
    });
    return JSON.parse(response.text.trim());
  } catch (error: any) {
    throw new Error("فشل في تحليل كشف الحساب.");
  }
};

import React, { useState, useEffect, useRef, useId, useMemo } from 'react';
import { Country } from '../types';
import { ChevronDown, Search, Check, X } from 'lucide-react';

interface CountryComboboxProps {
  label: string;
  countries: Country[];
  selectedCountry: Country | null;
  onSelect: (country: Country) => void;
  placeholder?: string;
  type?: 'origin' | 'destination';
}

const normalizeText = (text: string): string => {
  return text
    .toLowerCase()
    .replace(/[أإآ]/g, 'ا')
    .replace(/ة/g, 'ه')
    .replace(/ى/g, 'ي')
    .replace(/ؤ/g, 'و')
    .replace(/ئ/g, 'ي')
    .replace(/[^\w\s\u0600-\u06FF]/g, '')
    .trim();
};

const levenshteinDistance = (a: string, b: string): number => {
  if (a.length === 0) return b.length;
  if (b.length === 0) return a.length;
  const matrix = Array(b.length + 1).fill(null).map(() => Array(a.length + 1).fill(null));
  for (let i = 0; i <= b.length; i++) matrix[i][0] = i;
  for (let j = 0; j <= a.length; j++) matrix[0][j] = j;
  for (let i = 1; i <= b.length; i++) {
    for (let j = 1; j <= a.length; j++) {
      const cost = a[j - 1] === b[i - 1] ? 0 : 1;
      matrix[i][j] = Math.min(matrix[i - 1][j] + 1, matrix[i][j - 1] + 1, matrix[i - 1][j - 1] + cost);
    }
  }
  return matrix[b.length][a.length];
};

const CountryCombobox: React.FC<CountryComboboxProps> = ({
  label,
  countries,
  selectedCountry,
  onSelect,
  placeholder,
  type = 'origin'
}) => {
  const [isOpen, setIsOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [debouncedQuery, setDebouncedQuery] = useState('');
  const wrapperRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  const uniqueId = useId();
  const labelId = `label-${uniqueId}`;
  const listboxId = `listbox-${uniqueId}`;

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (wrapperRef.current && !wrapperRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  useEffect(() => {
    if (isOpen && inputRef.current) {
      setTimeout(() => inputRef.current?.focus(), 50);
    }
  }, [isOpen]);

  useEffect(() => {
    const timer = setTimeout(() => setDebouncedQuery(searchQuery), 200);
    return () => clearTimeout(timer);
  }, [searchQuery]);

  const searchableCountries = useMemo(() => {
    return countries.map(country => ({
      ...country,
      normAr: normalizeText(country.nameAr),
      normEn: normalizeText(country.nameEn)
    }));
  }, [countries]);

  const filteredCountries = useMemo(() => {
    const query = normalizeText(debouncedQuery);
    if (!query) return countries;
    return searchableCountries
      .map(item => {
        const { normAr, normEn, ...country } = item;
        let score = 999;
        let match = false;
        if (normAr === query || normEn === query) { score = 0; match = true; } 
        else if (normAr.startsWith(query) || normEn.startsWith(query)) { score = 10; match = true; } 
        else if (normAr.includes(query) || normEn.includes(query)) { score = 20; match = true; } 
        else if (query.length >= 3) {
          const distAr = levenshteinDistance(query, normAr);
          const distEn = levenshteinDistance(query, normEn);
          const threshold = Math.floor(query.length * 0.4) + 1;
          if (distAr <= threshold || distEn <= threshold) { score = 30 + Math.min(distAr, distEn); match = true; }
        }
        return { country, score, match };
      })
      .filter(item => item.match)
      .sort((a, b) => a.score - b.score)
      .map(item => item.country);
  }, [debouncedQuery, searchableCountries, countries]);

  const handleSelect = (country: Country) => {
    onSelect(country);
    setIsOpen(false);
    setSearchQuery('');
    setDebouncedQuery('');
  };

  const dynamicStyles = useMemo(() => {
    if (!selectedCountry) return {};
    return {
      borderColor: selectedCountry.color,
      boxShadow: isOpen ? `0 0 0 4px ${selectedCountry.color}20` : 'none'
    };
  }, [selectedCountry, isOpen]);

  const resolvedPlaceholder = placeholder || (type === 'origin' ? 'اختر دولة الجنسية / المغادرة' : 'اختر وجهة السفر المقصودة');

  return (
    <div className="w-full relative group" ref={wrapperRef}>
      <label 
        id={labelId}
        className={`block text-[10px] font-black mb-1.5 uppercase tracking-widest ${selectedCountry ? 'text-slate-900 dark:text-slate-200' : 'text-slate-400 dark:text-slate-500'}`}
      >
        {label}
      </label>

      <button
        type="button"
        onClick={() => setIsOpen(!isOpen)}
        aria-haspopup="listbox"
        aria-expanded={isOpen}
        aria-controls={listboxId}
        style={dynamicStyles}
        className={`
          w-full flex items-center justify-between 
          bg-white dark:bg-slate-900 border rounded-2xl px-4 py-3 text-right min-h-[64px]
          transition-all duration-300 relative z-10 focus:outline-none
          ${!selectedCountry ? 'border-slate-200 dark:border-slate-800 hover:border-emerald-400' : 'border-2'}
        `}
      >
        <span className="flex items-center gap-3 truncate text-right w-full">
          {selectedCountry ? (
            <>
              <div className="relative">
                <span className="text-2xl drop-shadow-sm">{selectedCountry.flag}</span>
                <div 
                  className="absolute -bottom-1 -right-1 w-3 h-3 rounded-full border-2 border-white dark:border-slate-900 shadow-sm" 
                  style={{ backgroundColor: selectedCountry.color }} 
                />
              </div>
              <div className="flex flex-col items-start overflow-hidden">
                <span className="font-bold text-slate-900 dark:text-white truncate">{selectedCountry.nameAr}</span>
                <span className="text-[9px] text-slate-400 uppercase font-black" style={{ color: selectedCountry.color }}>{selectedCountry.nameEn}</span>
              </div>
            </>
          ) : (
            <span className="text-slate-400 font-medium">{resolvedPlaceholder}</span>
          )}
        </span>
        <ChevronDown className={`w-5 h-5 transition-transform duration-300 ${isOpen ? 'rotate-180' : 'text-slate-300'}`} />
      </button>

      {isOpen && (
        <div className="absolute z-50 w-full mt-2 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-2xl shadow-2xl overflow-hidden animate-in fade-in slide-in-from-top-2 duration-200">
          <div className="p-3 border-b border-slate-100 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-900/50">
            <div className="relative">
              <Search className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
              <input
                ref={inputRef}
                type="text"
                className="w-full pr-10 pl-4 py-2.5 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl text-sm outline-none focus:ring-2 focus:ring-emerald-500/20"
                placeholder="ابحث باسم الدولة..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
            </div>
          </div>
          <ul id={listboxId} role="listbox" className="max-h-72 overflow-y-auto custom-scrollbar">
            {filteredCountries.length === 0 ? (
              <li className="px-6 py-10 text-center text-slate-400 text-sm italic">لا توجد نتائج مطابقة</li>
            ) : (
              filteredCountries.map((country) => (
                <li key={country.code}>
                  <button
                    onClick={() => handleSelect(country)}
                    className={`
                      w-full flex items-center justify-between px-4 py-3 text-right hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors
                      ${selectedCountry?.code === country.code ? 'bg-slate-50 dark:bg-slate-800' : ''}
                    `}
                  >
                    <span className="flex items-center gap-3">
                      <div className="relative">
                        <span className="text-xl">{country.flag}</span>
                        <div className="absolute -top-1 -left-1 w-2 h-2 rounded-full shadow-sm" style={{ backgroundColor: country.color }} />
                      </div>
                      <div className="flex flex-col items-start">
                        <span className="text-sm font-bold text-slate-700 dark:text-slate-200">{country.nameAr}</span>
                        <span className="text-[10px] text-slate-400 uppercase font-bold" style={{ color: `${country.color}CC` }}>{country.nameEn}</span>
                      </div>
                    </span>
                    {selectedCountry?.code === country.code && <Check className="w-4 h-4" style={{ color: country.color }} />}
                  </button>
                </li>
              ))
            )}
          </ul>
        </div>
      )}
    </div>
  );
};

export default CountryCombobox;

import React, { useState, useMemo } from 'react';
import { Country } from '../types';
import { COUNTRIES } from '../constants';
import { PlaneTakeoff, PlaneLanding, MousePointer2 } from 'lucide-react';

interface InteractiveMapProps {
  origin: Country | null;
  destination: Country | null;
  onSelectOrigin: (country: Country) => void;
  onSelectDestination: (country: Country) => void;
  theme: 'light' | 'dark';
}

const InteractiveMap: React.FC<InteractiveMapProps> = ({ 
  origin, 
  destination, 
  onSelectOrigin, 
  onSelectDestination,
  theme 
}) => {
  const [popup, setPopup] = useState<{ x: number; y: number; country: Country } | null>(null);

  const handleCountryClick = (e: React.MouseEvent, country: Country) => {
    e.stopPropagation();
    const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();
    setPopup({ 
      x: rect.left + rect.width / 2, 
      y: rect.top, 
      country 
    });
  };

  const closePopup = () => setPopup(null);

  return (
    <div 
      className={`
        relative w-full aspect-[16/9] rounded-3xl border border-slate-200 dark:border-slate-800 
        overflow-hidden group shadow-inner transition-colors duration-500
        bg-gradient-to-br from-slate-50 via-slate-100 to-slate-200 
        dark:from-slate-950 dark:via-slate-900 dark:to-slate-800
      `} 
      onClick={closePopup}
    >
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,rgba(16,185,129,0.05),transparent_70%)] pointer-events-none" />
      <div className="absolute inset-0 opacity-[0.03] dark:opacity-[0.05] pointer-events-none" 
           style={{ backgroundImage: 'radial-gradient(circle, currentColor 1px, transparent 1px)', backgroundSize: '30px 30px' }} />

      <div className="absolute inset-0 flex items-center justify-center p-8">
        <div className="text-center w-full">
            <div className="mb-4 flex flex-col items-center">
                <div className="w-16 h-16 bg-emerald-500/10 rounded-full flex items-center justify-center mb-4 ring-8 ring-emerald-500/5">
                    <MousePointer2 className="w-8 h-8 text-emerald-500 animate-bounce" />
                </div>
                <h3 className="text-xl font-black text-slate-800 dark:text-slate-200">الخريطة التفاعلية</h3>
                <p className="text-sm text-slate-500 dark:text-slate-400 mt-2 max-w-xs mx-auto">انقر على أي دولة لتحديدها كمصدر أو وجهة.</p>
            </div>

            <div className="flex flex-wrap justify-center gap-2 sm:gap-3 mt-6 max-w-2xl mx-auto">
                {COUNTRIES.slice(0, 18).map(country => {
                    const isOrigin = origin?.code === country.code;
                    const isDest = destination?.code === country.code;
                    const isActive = isOrigin || isDest;

                    return (
                        <button
                            key={country.code}
                            onClick={(e) => handleCountryClick(e, country)}
                            style={{ 
                              borderColor: isActive ? country.color : 'transparent',
                              boxShadow: isActive ? `0 0 15px ${country.color}40` : 'none'
                            }}
                            className={`
                                flex flex-col items-center p-2.5 sm:p-3 rounded-2xl border-2 transition-all duration-300 relative
                                ${isActive ? 'bg-white dark:bg-slate-900 scale-110 z-10' : 
                                  'bg-white/70 dark:bg-slate-900/70 backdrop-blur-sm hover:border-slate-300 dark:hover:border-slate-700 shadow-sm'}
                            `}
                        >
                            <span className="text-2xl mb-1 filter drop-shadow-sm">{country.flag}</span>
                            <span className="text-[9px] sm:text-[10px] font-bold text-slate-600 dark:text-slate-400 uppercase tracking-tighter">{country.code}</span>

                            {isOrigin && <div className="absolute -top-2 -right-2 bg-emerald-600 text-white p-1 rounded-full shadow-md animate-in zoom-in-50"><PlaneTakeoff className="w-3 h-3" /></div>}
                            {isDest && <div className="absolute -top-2 -right-2 bg-rose-600 text-white p-1 rounded-full shadow-md animate-in zoom-in-50"><PlaneLanding className="w-3 h-3" /></div>}
                        </button>
                    )
                })}
            </div>
        </div>
      </div>

      {popup && (
        <div 
          className="fixed z-[100] animate-in zoom-in-95 fade-in duration-200 -translate-x-1/2 -translate-y-[110%]"
          style={{ top: popup.y, left: popup.x }}
          onClick={(e) => e.stopPropagation()}
        >
          <div 
            className="bg-white/90 dark:bg-slate-900/95 backdrop-blur-xl border-2 shadow-2xl rounded-2xl p-2 min-w-[160px]"
            style={{ borderColor: popup.country.color }}
          >
            <div className="flex items-center gap-2 px-3 py-2 border-b border-slate-100 dark:border-slate-800 mb-1">
                <span className="text-xl">{popup.country.flag}</span>
                <span className="font-bold text-sm text-slate-900 dark:text-white">{popup.country.nameAr}</span>
            </div>
            <button 
                onClick={() => { onSelectOrigin(popup.country); closePopup(); }}
                className="w-full flex items-center justify-between gap-3 px-3 py-2 hover:bg-slate-50 dark:hover:bg-slate-800 rounded-lg transition-colors text-right"
            >
                <span className="text-xs font-bold text-emerald-600">تحديد كمصدر</span>
                <PlaneTakeoff className="w-4 h-4 text-emerald-500" />
            </button>
            <button 
                onClick={() => { onSelectDestination(popup.country); closePopup(); }}
                className="w-full flex items-center justify-between gap-3 px-3 py-2 hover:bg-slate-50 dark:hover:bg-slate-800 rounded-lg transition-colors text-right"
            >
                <span className="text-xs font-bold text-rose-600">تحديد كوجهة</span>
                <PlaneLanding className="w-4 h-4 text-rose-500" />
            </button>
          </div>
          <div className="w-3 h-3 bg-white dark:bg-slate-900 border-r border-b rotate-45 mx-auto -mt-1.5 shadow-sm" style={{ borderColor: popup.country.color }} />
        </div>
      )}
    </div>
  );
};

export default InteractiveMap;
